/**
 * WB Seller Auth — CDP-based approach.
 * Headless Puppeteer + F.A.C.C.T. antibot + CDP network interception.
 * Includes supplier mismatch protection.
 */
import puppeteer, { type Browser, type Page } from "puppeteer";
import { saveTokens, refreshSellerToken, checkApiSession, type WbTokens } from "./wb-seller-api";

// Singleton via globalThis (survives Next.js hot-reload)
const g = globalThis as unknown as {
  __wbCdpBrowser?: Browser | null;
  __wbCdpPage?: Page | null;
  __wbCdpSticker?: string;
};

// --- Supplier mismatch check ---
// After auth, compares supplierId from JWT with oid from API key.
// If different — returns warning to show in UI.

function checkSupplierMismatch(): string | null {
  const apiKey = fs.readFileSync("data/wb-api-key.txt", "utf-8").trim();
  const apiPayload = JSON.parse(Buffer.from(apiKey.split(".")[1], "base64").toString());
  const apiOid = String(apiPayload.oid || "");
  const tokens = JSON.parse(fs.readFileSync("data/wb-tokens.json", "utf-8"));
  const tokenSid = String(tokens.supplierId || "");

  if (apiOid && tokenSid && apiOid !== tokenSid) {
    return `API-ключ: кабинет ${apiOid}, авторизация: кабинет ${tokenSid}. Данные от разного юрлица!`;
  }
  return null;
}

// --- cdpSendPhone ---
// 1. Opens seller-auth.wildberries.ru (headless)
// 2. Waits for F.A.C.C.T. antibot SDK (window.gib)
// 3. Types phone into real UI (antibot generates captcha_token)
// 4. Intercepts captcha_token via CDP Network
// 5. Checks page state: code / ratelimit / captcha
// Returns: { ok, step: "code" | "error", warning? }

// --- cdpSubmitCode ---
// 1. Checks page is on wildberries.ru (not lost)
// 2. Types SMS code into InputCell fields
// 3. Intercepts /auth/v2/auth response via CDP
// 4. Extracts access_token from payload
// 5. Navigates to seller.wildberries.ru for cookies
// 6. Saves tokens + checks supplier mismatch
// Returns: { ok, step: "authenticated" | "error", warning? }

// --- saveAuthTokens ---
// 1. Navigate to seller.wildberries.ru (get all cookies)
// 2. Extract wbx-validation-key, x-supplier-id-external via CDP
// 3. Refresh wb-seller-lk via API
// 4. Save to data/wb-tokens.json

// --- Key: browser always headless: "new" ---
// Works on VPS without GUI.
// For debugging: change to headless: false temporarily.

"use client";
import { useState, useEffect, useRef } from "react";

type Step = "loading" | "phone" | "captcha" | "code" | "authenticated";

export function WbAuth() {
  const [step, setStep] = useState<Step>("loading");
  const [phone, setPhone] = useState("+7");
  const [code, setCode] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    // При загрузке — проверить сессию
    fetch("/api/wb/auth").then(r => r.json()).then(d => {
      setStep(d.ok ? "authenticated" : "phone");
    }).catch(() => setStep("phone"));
  }, []);

  function handleStepResult(data) {
    if (!data.ok && data.step === "error") {
      setError(data.error); return;
    }
    setError("");
    switch (data.step) {
      case "code": setCode(""); setStep("code"); break;
      case "authenticated":
        // Верифицируем что токены сохранились
        fetch("/api/wb/auth").then(r => r.json()).then(d => {
          if (d.ok) setStep("authenticated");
          else { setError("Токены не сохранились"); setStep("phone"); }
        }); break;
    }
  }

  // Шаг 1: Отправить номер
  async function handleSendPhone() {
    setLoading(true); setError("");
    const res = await fetch("/api/wb/auth", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ phone }),
    });
    handleStepResult(await res.json());
    setLoading(false);
  }

  // Шаг 2: Подтвердить SMS-код
  async function handleSubmitCode() {
    setLoading(true); setError("");
    const res = await fetch("/api/wb/auth/verify", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ code }),
    });
    handleStepResult(await res.json());
    setLoading(false);
  }

  // Выход
  async function handleLogout() {
    await fetch("/api/wb/auth", { method: "DELETE" });
    setStep("phone"); setPhone("+7");
  }

  // UI:
  // step === "phone" → input[tel] + кнопка "Получить код"
  // step === "code" → input[numeric] + кнопка "Подтвердить" + "Назад"
  // step === "authenticated" → зелёный статус + кнопка "Выйти"
  // step === "loading" → спиннер "Проверка сессии..."
}

import { NextRequest, NextResponse } from "next/server";
import { cdpSendPhone, cdpCheckSession, cdpLogout } from "@/lib/wb-auth-cdp";

// POST — начать авторизацию (отправить телефон)
export async function POST(req: NextRequest) {
  const { phone } = await req.json();
  if (!phone) return NextResponse.json({ ok: false, step: "error", error: "Укажите телефон" }, { status: 400 });
  const result = await cdpSendPhone(phone);
  return NextResponse.json(result);
}

// GET — проверить сессию
export async function GET() {
  const result = await cdpCheckSession();
  return NextResponse.json(result);
}

// DELETE — выйти
export async function DELETE() {
  cdpLogout();
  return NextResponse.json({ ok: true });
}

