import puppeteer from 'puppeteer';
import fs from 'fs';

// === НАСТРОЙКИ ===
const TARGET_URL = 'https://seller-auth.wildberries.ru/'; // URL сайта
const FILTER = '/auth/|/code/|/api/';                     // regex для фильтрации запросов
const OUTPUT = 'data/sniffed-requests.json';               // куда сохранить лог
const TIMEOUT = 300000;                                     // 5 минут на ручные действия

// === ЗАПУСК ===
const browser = await puppeteer.launch({
  headless: false,  // ВАЖНО: false чтобы видеть и взаимодействовать
  args: [
    '--no-sandbox',
    '--disable-blink-features=AutomationControlled',
    '--window-size=1280,900'
  ]
});

const page = (await browser.pages())[0];
await page.setViewport({ width: 1280, height: 800 });

// Скрыть признаки автоматизации
await page.evaluateOnNewDocument(() => {
  Object.defineProperty(navigator, 'webdriver', { get: () => false });
});

// === CDP ПЕРЕХВАТ ===
const client = await page.createCDPSession();
await client.send('Network.enable');

const requests = [];
const filter = new RegExp(FILTER);

// Перехват ИСХОДЯЩИХ запросов
client.on('Network.requestWillBeSent', (params) => {
  const url = params.request.url;
  if (!filter.test(url)) return;

  requests.push({
    url,
    method: params.request.method,
    headers: params.request.headers,
    body: params.request.postData || null,
    timestamp: new Date().toISOString(),
  });

  console.log(`\n>>> ${params.request.method} ${url}`);
  console.log('Headers:', JSON.stringify(params.request.headers, null, 2));
  if (params.request.postData) {
    console.log('Body:', params.request.postData);
  }
});

// Перехват ОТВЕТОВ
client.on('Network.responseReceived', (params) => {
  const url = params.response.url;
  if (!filter.test(url)) return;
  console.log(`\n<<< ${params.response.status} ${url}`);

  // Дописать статус к последнему запросу с тем же URL
  const last = [...requests].reverse().find(r => r.url === url);
  if (last) last.responseStatus = params.response.status;
});

// Перехват ТЕЛ ответов (опционально)
client.on('Network.loadingFinished', async (params) => {
  try {
    const { body, base64Encoded } = await client.send(
      'Network.getResponseBody', { requestId: params.requestId }
    );
    const last = [...requests].reverse().find(r => !r.responseBody);
    if (last) {
      last.responseBody = base64Encoded
        ? Buffer.from(body, 'base64').toString('utf-8').slice(0, 2000)
        : body.slice(0, 2000);
    }
  } catch {}
});

// === ЗАГРУЗКА СТРАНИЦЫ ===
await page.goto(TARGET_URL, { waitUntil: 'networkidle2', timeout: 30000 });

console.log('\n' + '='.repeat(60));
console.log('  Страница загружена. Выполняй действия в браузере.');
console.log('  Все запросы к ' + FILTER + ' перехватываются.');
console.log('  Ctrl+C для завершения.');
console.log('='.repeat(60) + '\n');

// Ждём пока пользователь выполнит действия
await new Promise(r => setTimeout(r, TIMEOUT));

// === СОХРАНЕНИЕ ===
fs.writeFileSync(OUTPUT, JSON.stringify(requests, null, 2));
console.log(`\nСохранено ${requests.length} запросов в ${OUTPUT}`);
await browser.close();

"""Alert system for position changes with cooldown."""

from datetime import datetime, timedelta, timezone
import db

COOLDOWN_MINUTES = 60  # Don't repeat same alert type within 1 hour


def check_alerts(telegram_id: int, article_id: int, sku: str, results: list[dict]) -> list[str]:
    """Check results against alert rules. Skips errors. Respects cooldown."""
    alert_configs = {a["alert_type"]: a for a in db.get_alerts(telegram_id)}
    messages = []

    queries = db.get_queries(telegram_id, article_id)
    query_map = {q["query"]: q for q in queries}

    now = datetime.now(timezone.utc)

    for r in results:
        if r.get("error"):
            continue

        query = r["query"]
        position = r["position"]
        query_obj = query_map.get(query)
        if not query_obj:
            continue

        prev = db.get_previous_result(telegram_id, article_id, query_obj["id"])

        # Alert 1: position dropped below threshold
        cfg = alert_configs.get("position_drop_below", {})
        if cfg.get("enabled") and position is not None:
            if _check_cooldown(cfg):
                threshold = cfg.get("threshold", 50)
                if position > threshold:
                    messages.append(
                        f"⚠️ SKU {sku} | \"{query}\"\n"
                        f"Позиция {position} — ниже порога {threshold}")
                    db.mark_alert_fired(telegram_id, "position_drop_below", query)

        # Alert 2: disappeared from search
        cfg = alert_configs.get("disappeared", {})
        if cfg.get("enabled") and position is None:
            if _check_cooldown(cfg):
                if prev and prev.get("position") is not None:
                    messages.append(
                        f"🔴 SKU {sku} | \"{query}\"\n"
                        f"Товар пропал из выдачи! (был на позиции {prev['position']})")
                    db.mark_alert_fired(telegram_id, "disappeared", query)

        # Alert 3: position changed significantly
        cfg = alert_configs.get("position_change", {})
        if cfg.get("enabled") and position is not None:
            if _check_cooldown(cfg):
                threshold = cfg.get("threshold", 10)
                if prev and prev.get("position") is not None:
                    diff = position - prev["position"]
                    if abs(diff) >= threshold:
                        direction = "упала" if diff > 0 else "выросла"
                        emoji = "📉" if diff > 0 else "📈"
                        messages.append(
                            f"{emoji} SKU {sku} | \"{query}\"\n"
                            f"Позиция {direction}: {prev['position']} → {position} ({'+' if diff > 0 else ''}{diff})")
                        db.mark_alert_fired(telegram_id, "position_change", query)

    return messages


def _check_cooldown(cfg: dict) -> bool:
    """Check if enough time passed since last alert of this type."""
    last_fired = cfg.get("last_fired_at")
    if not last_fired:
        return True
    try:
        last_dt = datetime.fromisoformat(last_fired).replace(tzinfo=timezone.utc)
        now = datetime.now(timezone.utc)
        return (now - last_dt) > timedelta(minutes=COOLDOWN_MINUTES)
    except Exception:
        return True

/**
 * SQLite storage for reviews module (accounts, reviews, stats).
 * Uses the existing finance.db database.
 */

import Database from "better-sqlite3";
import path from "path";

const DB_PATH = path.join(process.cwd(), "data", "finance.db");

let db: Database.Database | null = null;

function getDb(): Database.Database {
  if (!db) {
    db = new Database(DB_PATH, { readonly: false });
    db.pragma("journal_mode = WAL");
  }
  return db;
}

