            ? `В базе: ${fmtN(finalCount)} ✅ | Цена и ПВЗ: ${fmtN(enrichedTotal)}`
            : `В базе: ${fmtN(finalCount)} ✅`,
        });
      }).catch(() => {
        const fmtN = (n: number) => n.toLocaleString("ru-RU");
        const finalCount = getReviewsCount(account.id);
        setSyncStatusDb({ loaded: finalCount, total: finalCount, status: "done", message: `В базе: ${fmtN(finalCount)} ✅` });
      });
    }

    const filters = {
      account_id: sp.get("account_id") ? Number(sp.get("account_id")) : undefined,
      date_from: sp.get("date_from") || undefined,
      date_to: sp.get("date_to") || undefined,
      rating: sp.get("rating") || undefined,
      status: sp.get("status") || undefined,
      complaint_status: sp.get("complaint_status") || undefined,
      is_hidden:
        sp.get("is_hidden") !== null && sp.get("is_hidden") !== ""
          ? Number(sp.get("is_hidden"))
          : undefined,
      is_updated:
        sp.get("is_updated") !== null && sp.get("is_updated") !== ""
          ? Number(sp.get("is_updated"))
          : undefined,
      is_excluded_rating:
        sp.get("is_excluded_rating") !== null && sp.get("is_excluded_rating") !== ""
          ? Number(sp.get("is_excluded_rating"))
          : undefined,
      purchase_type: sp.get("purchase_type") || undefined,
      search_product: sp.get("search_product") || undefined,
      search_article: sp.get("search_article") || undefined,
      search_text: sp.get("search_text") || undefined,
      search_buyer: sp.get("search_buyer") || undefined,
      search_comment: sp.get("search_comment") || undefined,
      wb_review_id: sp.get("wb_review_id") || undefined,
      buyer_chat_id: sp.get("buyer_chat_id") || undefined,
      page: sp.get("page") ? Number(sp.get("page")) : 1,
      per_page: sp.get("per_page") ? Number(sp.get("per_page")) : 25,
      sort_by: sp.get("sort_by") || "date",
      sort_dir: (sp.get("sort_dir") as "asc" | "desc") || "desc",
    };

    const result = getReviews(filters);
    return NextResponse.json(result);
  } catch (e: unknown) {
    return NextResponse.json({ error: (e as Error).message }, { status: 500 });
  }
}

#!/usr/bin/env node
/**
 * Auto-complaints script — runs every 30 minutes.
 * For each account with auto_complaints=1 and cabinet tokens:
 * 1. Finds reviews eligible for complaint (matching ratings, no existing complaint)
 * 2. Submits complaints to WB Cabinet API
 * 3. Logs results
 *
 * Usage: node scripts/reviews-complaints.js
 */

const Database = require("better-sqlite3");
const path = require("path");
const fs = require("fs");

const PROJECT_DIR = path.join(__dirname, "..");
const DB_PATH = path.join(PROJECT_DIR, "data", "finance.db");
const LOG_PATH = path.join(PROJECT_DIR, "data", "reviews-complaints.log");

const WB_COMPLAINTS_URL =
  "https://seller-reviews.wildberries.ru/ns/fa-seller-api/reviews-ext-seller-portal/api/v1/feedbacks/complaints";

// ─── Logging ────────────────────────────────────────────────

function log(msg) {
  const line = `[${new Date().toISOString()}] ${msg}`;
  console.log(line);
  try { fs.appendFileSync(LOG_PATH, line + "\n"); } catch {}
}

// ─── DB helpers ─────────────────────────────────────────────

function getDb() {
  const db = new Database(DB_PATH, { readonly: false });
  db.pragma("journal_mode = WAL");
  return db;
}

function initComplaintsTable(db) {
  db.exec(`
    CREATE TABLE IF NOT EXISTS review_complaints (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      review_id INTEGER REFERENCES reviews(id),
      account_id INTEGER REFERENCES review_accounts(id),
      wb_review_id TEXT NOT NULL,
      complaint_reason_id INTEGER NOT NULL,
      explanation TEXT,
      status TEXT DEFAULT 'pending',
      error_message TEXT,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      submitted_at DATETIME,
      resolved_at DATETIME
    )
  `);
}

function getAutoComplaintAccounts(db) {
  return db.prepare(`
    SELECT * FROM review_accounts
    WHERE auto_complaints = 1
      AND wb_authorize_v3 IS NOT NULL
      AND wb_authorize_v3 != ''
  `).all();
}

function getComplaintsConfig(account) {
  const defaults = {
    ratings: [1, 2],
    allowed_reasons: [11, 13, 16, 20],
    excluded_articles: "",
    daily_limit: 50,
    delay_min_minutes: 1,
    delay_max_minutes: 10,
    managers: [],
  };
  try {
    const settings = account.settings_json ? JSON.parse(account.settings_json) : {};
    return { ...defaults, ...settings.auto_complaints_config };
  } catch {
    return defaults;
  }
}

function getEligibleReviews(db, accountId, ratings, excludedArticles) {
  const ratingPlaceholders = ratings.map(() => "?").join(",");
  const params = [accountId, ...ratings];

  let excludeClause = "";
  if (excludedArticles.length > 0) {
    const artPlaceholders = excludedArticles.map(() => "?").join(",");
    excludeClause = `AND product_article NOT IN (${artPlaceholders})`;
    params.push(...excludedArticles);
  }

  return db.prepare(`
    SELECT * FROM reviews
    WHERE account_id = ?
      AND rating IN (${ratingPlaceholders})
      AND complaint_status IS NULL
      AND is_hidden = 0
      AND is_excluded_rating = 0
      AND wb_review_id IS NOT NULL
      ${excludeClause}
    ORDER BY date DESC
  `).all(...params);
}

function getTodayCount(db, accountId) {
  const row = db.prepare(`
    SELECT COUNT(*) as cnt FROM review_complaints
    WHERE account_id = ? AND date(created_at) = date('now')
  `).get(accountId);
  return row.cnt;
}

// ─── AI text generation via Claude Code CLI ────────────────

const COMPLAINT_REASONS = {
  11: "Отзыв не относится к товару",
  12: "Отзыв оставили конкуренты",
  13: "Спам-реклама в тексте",
  16: "Нецензурная лексика",
  18: "Отзыв с политическим контекстом",
  20: "Угрозы, оскорбления",
  19: "Другое",
};

const DEFAULT_SYSTEM_PROMPT = "Ты — сотрудник бренда IMSI (женское нижнее бельё) на Wildberries. Ты составляешь обращения к модератору по отзывам покупателей. Пиши как живой человек. Отвечай только JSON.";

const DEFAULT_USER_PROMPT = `Составь обращение к модератору Wildberries по отзыву покупателя.

Отзыв:
- Товар: {product_name} (арт. {product_article})
- Оценка: {rating}/5
- Текст: {review_text}
- Фото/видео от покупателя: нет

Категории обращения (выбери одну):
{reasons_list}

Правила:
- НЕ используй фразы: «голословный», «добросовестный продавец», «просим модератора рассмотреть», «принять решение об удалении», «вводит в заблуждение», «наносит ущерб репутации», «на всех этапах», «бездоказательный», «потенциальных покупателей», «репутационный ущерб»
- Реагируй на содержание конкретного отзыва, а не по шаблону:
  * отзыв пустой → отсутствие содержания, нарушение правил площадки
  * есть текст но нет фото → нет подтверждения заявленному
  * эмоциональный отзыв → субъективная оценка без конкретики
  * претензия к размеру/качеству → неправильный подбор размера, несоблюдение рекомендаций по уходу

Ответ — строго JSON, одной строкой:
{"reason_id": <число>, "explanation": "<текст обращения>"}`;

function buildPrompt(template, review, allowedReasons) {
  const reviewText = [
    review.review_text,
    review.pros ? `Достоинства: ${review.pros}` : "",
    review.cons ? `Недостатки: ${review.cons}` : "",
  ].filter(Boolean).join("\n");

  const reasonsList = allowedReasons
    .map((id) => `  ${id} — ${COMPLAINT_REASONS[id] || "Неизвестно"}`)
    .join("\n");

  return template
    .replace(/\{product_name\}/g, review.product_name || "неизвестен")
    .replace(/\{product_article\}/g, review.product_article || "?")
    .replace(/\{rating\}/g, String(review.rating || "?"))
    .replace(/\{review_text\}/g, reviewText || "(покупатель не оставил текст)")
    .replace(/\{reasons_list\}/g, reasonsList);
}

function generateComplaint(review, allowedReasons, config, manager, previousText) {
  return new Promise((resolve) => {
    const sysPrompt = (config && config.system_prompt) || DEFAULT_SYSTEM_PROMPT;
    const userTemplate = (config && config.user_prompt) || DEFAULT_USER_PROMPT;
    let prompt = buildPrompt(userTemplate, review, allowedReasons);

    if (manager && manager.style) {
      prompt += `\n\n---\nПиши в стиле менеджера ${manager.name}: ${manager.style}`;
      if (previousText) {
        prompt += `\n\nТвоё предыдущее обращение (НЕ повторяй структуру, формулировки и порядок аргументов):\n"${previousText.slice(0, 500)}"`;
      }
    }

    const { spawn } = require("child_process");
    const proc = spawn("/opt/homebrew/bin/claude", ["-p", "--model", "opus", "--effort", "max", "--append-system-prompt", sysPrompt], {
      timeout: 120000,
      env: { ...process.env, HOME: "/Users/octopus" },
    });

    let stdout = "";
    let stderr = "";
    proc.stdout.on("data", (d) => { stdout += d.toString(); });
    proc.stderr.on("data", (d) => { stderr += d.toString(); });
    proc.stdin.write(prompt);
    proc.stdin.end();

    proc.on("close", (code) => {
      if (code !== 0) {
        log(`  AI generation failed: ${stderr || `exit code ${code}`}`);
        resolve(null);
        return;
      }
      try {
        const text = stdout.trim();
        const jsonMatch = text.match(/\{[\s\S]*"reason_id"[\s\S]*"explanation"[\s\S]*\}/);
        if (!jsonMatch) { log(`  AI no JSON found in output`); resolve(null); return; }
        const parsed = JSON.parse(jsonMatch[0]);
        if (!allowedReasons.includes(parsed.reason_id)) {
          parsed.reason_id = allowedReasons[0];
        }
        resolve(parsed);
      } catch (e) {
        log(`  AI JSON parse failed: ${e.message}`);
        resolve(null);
      }
    });
  });
}

// ─── WB API ─────────────────────────────────────────────────

function buildHeaders(account) {
  const headers = {
    "Content-Type": "application/json",
    "Origin": "https://seller.wildberries.ru",
  };
  if (account.wb_authorize_v3) headers["Authorizev3"] = account.wb_authorize_v3;
  if (account.wb_validation_key) {
    headers["Cookie"] = `wbx-validation-key=${account.wb_validation_key}; x-supplier-id-external=e0334427-4f82-4bc3-a0ab-43394e58b6ac`;
  }
  return headers;
}

async function submitComplaint(account, wbReviewId, reasonId, explanation) {
  const headers = buildHeaders(account);
  const complaint = { id: reasonId };
  if (explanation) complaint.explanation = explanation;
  const body = JSON.stringify({
    feedbackId: wbReviewId,
    feedbackComplaint: complaint,
  });

  const res = await fetch(WB_COMPLAINTS_URL, {
    method: "PATCH",
    headers,
    body,
  });

  const text = await res.text().catch(() => "");

  // WB returns 200 even on auth errors — check body for "error": true
  let wbOk = res.ok;
  if (wbOk && text) {
    try {
      const parsed = JSON.parse(text);
      if (parsed.error === true) wbOk = false;
    } catch {}
  }

  return { ok: wbOk, status: res.status, body: text };
}

// ─── Sync complaint statuses from WB ────────────────────────

async function syncComplaintStatuses(db, account) {
  const pending = db.prepare("SELECT id, wb_review_id, review_id FROM review_complaints WHERE account_id = ? AND status = 'submitted'").all(account.id);
  if (pending.length === 0) return;

  log(`  Checking ${pending.length} pending complaint statuses...`);
  const headers = buildHeaders(account);
  const pendingMap = new Map(pending.map(p => [p.wb_review_id, p]));
  let updated = 0;

  // Paginate through feedbacks using pages.next cursor
  let nextCursor = "";
  for (let page = 0; page < 30 && pendingMap.size > 0; page++) {
    const cursorParam = nextCursor ? `cursor=${encodeURIComponent(nextCursor)}` : "cursor=";
    const url = `https://seller-reviews.wildberries.ru/ns/fa-seller-api/reviews-ext-seller-portal/api/v2/feedbacks?${cursorParam}&isAnswered=true&limit=100&sortOrder=dateDesc`;
    const res = await fetch(url, { headers, signal: AbortSignal.timeout(15000) }).catch(() => null);
    if (!res || !res.ok) break;

    const data = await res.json().catch(() => null);
    if (!data || data.error) break;
    const feedbacks = data.data?.feedbacks || [];
    if (feedbacks.length === 0) break;

    for (const fb of feedbacks) {
      if (!pendingMap.has(fb.id)) continue;
      const status = fb.supplierComplaints?.feedbackComplaint?.status;
      if (status === 'approved' || status === 'rejected') {
        const complaint = pendingMap.get(fb.id);
        db.prepare("UPDATE review_complaints SET status = ?, resolved_at = CURRENT_TIMESTAMP WHERE id = ?").run(status, complaint.id);
        db.prepare("UPDATE reviews SET complaint_status = ? WHERE wb_review_id = ?").run(status, fb.id);
        pendingMap.delete(fb.id);
        updated++;
        log(`  ${fb.id}: ${status}`);
      }
    }

    nextCursor = data.data?.pages?.next || "";
    if (!nextCursor) break;
    await new Promise(r => setTimeout(r, 150));
  }

  log(`  Status sync: ${updated} updated, ${pendingMap.size} still pending`);
}

// ─── Main ───────────────────────────────────────────────────

async function main() {
  log("=== Auto-complaints started ===");

  const db = getDb();
  initComplaintsTable(db);

  const accounts = getAutoComplaintAccounts(db);
  if (accounts.length === 0) {
    log("No accounts with auto_complaints enabled");
    db.close();
    return;
  }

  const stmtInsert = db.prepare(`
    INSERT INTO review_complaints (review_id, account_id, wb_review_id, complaint_reason_id, explanation, manager_name)
    VALUES (?, ?, ?, ?, ?, ?)
  `);
  const stmtSubmitted = db.prepare(`
    UPDATE review_complaints SET status = 'submitted', submitted_at = CURRENT_TIMESTAMP WHERE id = ?
  `);
  const stmtError = db.prepare(`
    UPDATE review_complaints SET status = 'error', error_message = ? WHERE id = ?
  `);
  const stmtReviewStatus = db.prepare(`
    UPDATE reviews SET complaint_status = ? WHERE id = ?
  `);

  for (const account of accounts) {
    log(`Processing account: ${account.name} (id=${account.id})`);

    // Sync statuses of previously submitted complaints
    try {
      await syncComplaintStatuses(db, account);
    } catch (e) {
      log(`  Status sync error: ${e.message}`);
    }

    const config = getComplaintsConfig(account);
    const todayCount = getTodayCount(db, account.id);
    const remaining = Math.max(0, config.daily_limit - todayCount);

    if (remaining === 0) {
      log(`  Daily limit reached (${config.daily_limit}), skipping`);
      continue;
    }

    const excludedArticles = config.excluded_articles
      ? config.excluded_articles.split(/[,\n]/).map(s => s.trim()).filter(Boolean)
      : [];

    const reviews = getEligibleReviews(db, account.id, config.ratings, excludedArticles);
    const toSubmit = reviews.slice(0, remaining);

    log(`  Eligible: ${reviews.length}, today used: ${todayCount}/${config.daily_limit}, will submit: ${toSubmit.length}`);

    let submitted = 0;
    let errors = 0;

    for (const review of toSubmit) {
      // Pick random manager
      const managers = config.managers && config.managers.length > 0 ? config.managers : [{ name: "Default", style: "" }];
      const manager = managers[Math.floor(Math.random() * managers.length)];
      const previousText = db.prepare("SELECT explanation FROM review_complaints WHERE account_id = ? AND manager_name = ? AND explanation IS NOT NULL ORDER BY id DESC LIMIT 1").get(account.id, manager.name);

      // AI selects reason + generates complaint text
      const ai = await generateComplaint(review, config.allowed_reasons, config, manager, previousText?.explanation || null);
      if (!ai) {
        log(`  AI failed for ${review.wb_review_id}, skipping`);
        continue;
      }
      const { reason_id: reasonId, explanation } = ai;
      log(`  [${manager.name}] ${review.wb_review_id}: reason=${reasonId}, text="${(explanation || "").slice(0, 80)}..."`);

      const result = stmtInsert.run(review.id, account.id, review.wb_review_id, reasonId, explanation, manager.name);
      const complaintId = result.lastInsertRowid;

      try {
        const res = await submitComplaint(account, review.wb_review_id, reasonId, explanation);

        if (res.ok) {
          stmtSubmitted.run(complaintId);
          stmtReviewStatus.run("submitted", review.id);
          submitted++;
        } else {
          const errMsg = `HTTP ${res.status}: ${res.body.slice(0, 200)}`;
          stmtError.run(errMsg, complaintId);
          errors++;
          log(`  ERROR on review ${review.wb_review_id}: ${errMsg}`);

          // Stop on auth errors
          if (res.status === 401 || res.status === 403) {
            log(`  Auth error, stopping for this account`);
            break;
          }
        }
      } catch (e) {
        stmtError.run(e.message, complaintId);
        errors++;
        log(`  EXCEPTION on review ${review.wb_review_id}: ${e.message}`);
      }

      // Random delay between requests
      if (toSubmit.indexOf(review) < toSubmit.length - 1) {
        const delayMs = (config.delay_min_minutes + Math.random() * (config.delay_max_minutes - config.delay_min_minutes)) * 60 * 1000;
        const delayMin = (delayMs / 60000).toFixed(1);
        log(`  Waiting ${delayMin} min before next complaint...`);
        await new Promise(r => setTimeout(r, delayMs));
      }
    }

    log(`  Done: submitted=${submitted}, errors=${errors}`);
  }

  log("=== Auto-complaints finished ===");
  db.close();
}

main().catch(e => {
  log(`FATAL: ${e.message}`);
  process.exit(1);
});

#!/usr/bin/env node
/**
 * Reviews auto-sync script — runs every 10 minutes.
 * 1. Fetches new reviews (incremental: unanswered + last 500 answered)
 * 2. Enriches with price & region from Orders API
 *
 * Usage: node scripts/reviews-sync.js
 * Or via cron/launchd every 10 minutes.
 */

const Database = require("better-sqlite3");
const path = require("path");

const PROJECT_DIR = path.join(__dirname, "..");
const DB_PATH = path.join(PROJECT_DIR, "data", "finance.db");
const LOG_PATH = path.join(PROJECT_DIR, "data", "reviews-sync.log");
const fs = require("fs");

// ─── Logging ────────────────────────────────────────────────

function log(msg) {
  const line = `[${new Date().toISOString()}] ${msg}`;
  console.log(line);
  try { fs.appendFileSync(LOG_PATH, line + "\n"); } catch {}
}

// ─── DB helpers ─────────────────────────────────────────────

function getDb() {
  const db = new Database(DB_PATH, { readonly: false });
  db.pragma("journal_mode = WAL");
  return db;
}

function getApiKey(db) {
  const row = db.prepare(`SELECT api_key FROM review_accounts WHERE supplier_id = '1166225'`).get();
  return row?.api_key || null;
}

function getAccountId(db) {
  const row = db.prepare(`SELECT id FROM review_accounts WHERE supplier_id = '1166225'`).get();
  return row?.id || null;
}

// ─── Fetch feedbacks ────────────────────────────────────────

const WB_FEEDBACKS_URL = "https://feedbacks-api.wildberries.ru/api/v1/feedbacks";

async function fetchFeedbacks(apiKey) {
  const all = [];

  // 1) Unanswered
  for (let skip = 0; ; skip += 100) {
    const res = await fetch(`${WB_FEEDBACKS_URL}?isAnswered=false&take=100&skip=${skip}`, {
      headers: { Authorization: `Bearer ${apiKey}` },
    });
    if (!res.ok) break;
    const data = await res.json();
    const fbs = data.data?.feedbacks ?? [];
    all.push(...fbs);
    if (fbs.length < 100) break;
    await new Promise(r => setTimeout(r, 350));
  }

  // 2) Last 500 answered
  const res = await fetch(`${WB_FEEDBACKS_URL}?isAnswered=true&take=500&skip=0`, {
    headers: { Authorization: `Bearer ${apiKey}` },
  });
  if (res.ok) {
    const data = await res.json();
    const fbs = data.data?.feedbacks ?? [];
    all.push(...fbs);
  }

  return all;
}

// ─── Upsert reviews ────────────────────────────────────────

function upsertReviews(db, accountId, feedbacks) {
  const stmt = db.prepare(`
    INSERT INTO reviews (account_id, wb_review_id, date, rating, product_name, product_article, brand, review_text, pros, cons, buyer_name, status, is_updated, purchase_type, shk_id, order_date, bables)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    ON CONFLICT(wb_review_id) DO UPDATE SET
      review_text = excluded.review_text,
      pros = excluded.pros,
      cons = excluded.cons,
      rating = excluded.rating,
      purchase_type = excluded.purchase_type,
      shk_id = excluded.shk_id,
      order_date = excluded.order_date,
      bables = excluded.bables,
      is_updated = CASE WHEN reviews.review_text != excluded.review_text THEN 1 ELSE reviews.is_updated END
  `);

  let count = 0;
  db.transaction(() => {
    for (const fb of feedbacks) {
      const status = fb.isAnswered ? "replied" : "new";
      const purchaseType = fb.orderStatus === "buyout" ? "buyout"
        : fb.orderStatus === "rejected" ? "rejected"
        : fb.orderStatus === "returned" ? "returned"
        : null;
      stmt.run(
        accountId,
        fb.id,
        fb.createdDate ? fb.createdDate.slice(0, 10) : new Date().toISOString().slice(0, 10),
        fb.productValuation ?? 5,
        fb.productDetails?.productName || null,
        fb.productDetails?.nmId ? String(fb.productDetails.nmId) : fb.productDetails?.supplierArticle || null,
        fb.productDetails?.brandName || null,
        fb.text || null,
        fb.pros || null,
        fb.cons || null,
        fb.userName || null,
        status,
        0,
        purchaseType,
        fb.lastOrderShkId || null,
        fb.lastOrderCreatedAt ? fb.lastOrderCreatedAt.slice(0, 10) : null,
        fb.bables && fb.bables.length > 0 ? JSON.stringify(fb.bables) : null,
      );
      count++;
    }
  })();
  return count;
}

// ─── Enrich from Orders API ─────────────────────────────────

async function enrichFromOrders(db, apiKey, accountId) {
  const reviews = db.prepare(`
    SELECT id, shk_id FROM reviews
    WHERE account_id = ? AND shk_id IS NOT NULL AND (price IS NULL OR pickup_point IS NULL)
      AND order_date >= date('now', '-90 days')
    LIMIT 50000
  `).all(accountId);

  if (reviews.length === 0) return 0;

  const shkLookup = new Map();
  for (const r of reviews) shkLookup.set(r.shk_id, r.id);

  const dateFrom = new Date(Date.now() - 30 * 86400000).toISOString().slice(0, 10);
  const res = await fetch(`https://statistics-api.wildberries.ru/api/v1/supplier/orders?dateFrom=${dateFrom}`, {
    headers: { Authorization: apiKey },
  });
  if (!res.ok) return 0;

  const orders = await res.json();
  if (!Array.isArray(orders)) return 0;

  const stmt = db.prepare(`UPDATE reviews SET price = ?, pickup_point = ? WHERE shk_id = ? AND (price IS NULL OR pickup_point IS NULL)`);
  let enriched = 0;

  db.transaction(() => {
    for (const o of orders) {
      const sticker = Number(o.sticker);
      const price = Math.abs(o.finishedPrice || 0);
      if (sticker && shkLookup.has(sticker) && price > 0) {
        const res = stmt.run(price, o.regionName || "", sticker);
        enriched += res.changes;
        shkLookup.delete(sticker);
      }
    }
  })();

  return enriched;
}

// ─── Main ───────────────────────────────────────────────────

async function main() {
  log("=== Reviews sync started ===");

  const db = getDb();
  const apiKey = getApiKey(db);
  if (!apiKey) {
    log("ERROR: No API key found");
    db.close();
    return;
  }

  const accountId = getAccountId(db);
  if (!accountId) {
    log("ERROR: No account found");
    db.close();
    return;
  }

  // 1. Fetch & upsert reviews
  const feedbacks = await fetchFeedbacks(apiKey);
  log(`Fetched ${feedbacks.length} feedbacks from WB`);

  if (feedbacks.length > 0) {
    const before = db.prepare(`SELECT COUNT(*) as cnt FROM reviews WHERE account_id = ?`).get(accountId).cnt;
    const upserted = upsertReviews(db, accountId, feedbacks);
    const after = db.prepare(`SELECT COUNT(*) as cnt FROM reviews WHERE account_id = ?`).get(accountId).cnt;
    const added = after - before;
    log(`Upserted ${upserted}, new: ${added}, total: ${after}`);
  }

  // 2. Enrich from Orders API
  const enriched = await enrichFromOrders(db, apiKey, accountId);
  log(`Enriched ${enriched} reviews with price & region`);

  // 3. Update sync status
  const total = db.prepare(`SELECT COUNT(*) as cnt FROM reviews`).get().cnt;
  const withPrice = db.prepare(`SELECT COUNT(*) as cnt FROM reviews WHERE price > 0`).get().cnt;
  db.prepare(`UPDATE sync_status SET status = 'done', loaded = ?, total = ?, message = ?, updated_at = CURRENT_TIMESTAMP WHERE id = 1`)
    .run(total, total, `В базе: ${total.toLocaleString("ru-RU")} ✅ | Цена и ПВЗ: ${withPrice.toLocaleString("ru-RU")}`);

  log(`=== Done. Total: ${total}, with price: ${withPrice} ===`);
  db.close();
}

main().catch(e => {
  log(`FATAL: ${e.message}`);
  process.exit(1);
});

#!/usr/bin/env node
/**
 * Standalone daily sync script — runs independently of Next.js.
 * Called by macOS launchd every hour (06:00–23:00).
 *
 * Pulls 3 data sources for yesterday into SQLite:
 * 1. Realization report (seller-services API)
 * 2. Advertising expenses (advert-api)
 * 3. Orders (seller-analytics-api)
 */

const fs = require("fs");
const path = require("path");
const Database = require("better-sqlite3");

const PROJECT_DIR = path.join(__dirname, "..");
const DB_PATH = path.join(PROJECT_DIR, "data", "finance.db");
const STATUS_PATH = path.join(PROJECT_DIR, "data", "daily-sync-status.json");
const TOKENS_PATH = path.join(PROJECT_DIR, "data", "wb-tokens.json");
const API_KEY_PATH = path.join(PROJECT_DIR, "data", "wb-api-key.txt");
const REPORTS_DIR = path.join(PROJECT_DIR, "data", "reports");
const EXTRACT_DIR = path.join(REPORTS_DIR, "extracted");

const LOG_PATH = path.join(PROJECT_DIR, "data", "daily-sync.log");

// --- Logging ---

function log(msg) {
  const line = `[${new Date().toISOString()}] ${msg}`;
  console.log(line);
  try {
    fs.appendFileSync(LOG_PATH, line + "\n");
  } catch { /* ignore */ }
}

// --- Helpers ---

function yesterday() {
  // Use Moscow timezone (UTC+3) to determine "yesterday"
  const now = new Date();
  const msk = new Date(now.getTime() + 3 * 60 * 60 * 1000); // UTC+3
  msk.setDate(msk.getDate() - 1);
  return msk.toISOString().slice(0, 10);
}

function getApiKey() {
  try {
    if (fs.existsSync(API_KEY_PATH)) return fs.readFileSync(API_KEY_PATH, "utf-8").trim();
  } catch { /* ignore */ }
  return "";
}

function ensureDirs() {
  for (const d of [path.join(PROJECT_DIR, "data"), REPORTS_DIR, EXTRACT_DIR]) {
    if (!fs.existsSync(d)) fs.mkdirSync(d, { recursive: true });
  }
}

function loadStatus() {
  try {
    if (fs.existsSync(STATUS_PATH)) return JSON.parse(fs.readFileSync(STATUS_PATH, "utf-8"));
  } catch { /* ignore */ }
  return { today: null, lastRun: null, nextRun: null, running: false, history: [] };
}

function saveStatus(status) {
  fs.writeFileSync(STATUS_PATH, JSON.stringify(status, null, 2));
}

// --- Source 1: Realization report ---

const COL_MAP = {
  "Предмет": "subject_name", "Код номенклатуры": "nm_id", "Бренд": "brand_name",
  "Артикул поставщика": "sa_name", "Размер": "ts_name", "Баркод": "barcode",
  "Обоснование для оплаты": "supplier_oper_name", "Дата заказа покупателем": "order_dt",
  "Дата продажи": "sale_dt", "Кол-во": "quantity", "Цена розничная": "retail_price",
  "Цена розничная с учетом согласованной скидки": "retail_price_withdisc_rub",
  "Вайлдберриз реализовал Товар (Пр)": "retail_amount",
  "К перечислению Продавцу за реализованный Товар": "ppvz_for_pay",
  "Вознаграждение с продаж до вычета услуг поверенного, без НДС": "ppvz_sales_commission",
  "Эквайринг/Комиссии за организацию платежей": "acquiring_fee",
  "Услуги по доставке товара покупателю": "delivery_rub",
  "Количество доставок": "delivery_amount", "Количество возврата": "return_amount",
  "Хранение": "storage_fee", "Общая сумма штрафов": "penalty",
  "Операции на приемке": "acceptance",
  "Возмещение издержек по перевозке/по складским операциям с товаром": "rebill_logistic_cost",
  "Разовое изменение срока перечисления денежных средств": "additional_payment",
  "Итоговый кВВ без НДС, %": "ppvz_kvw_prc", "Размер кВВ без НДС, % Базовый": "ppvz_kvw_prc_base",
  "Скидка постоянного Покупателя (СПП), %": "ppvz_spp_prc", "Размер кВВ, %": "commission_percent",
  "Страна": "site_country", "Наименование офиса доставки": "office_name",
  "Удержания": "deduction", "Виды логистики, штрафов и корректировок ВВ": "bonus_type_name",
};

async function syncReport(date) {
  const result = { ok: false, value: 0, stable: true, prevValue: 0, lastAttempt: new Date().toISOString(), error: undefined };

  try {
    if (!fs.existsSync(TOKENS_PATH)) { result.error = "Нет токенов (authorizev3)"; return result; }
    const tokens = JSON.parse(fs.readFileSync(TOKENS_PATH, "utf-8"));
    if (!tokens.authorizev3 || !tokens.cookies) { result.error = "Неполные токены"; return result; }

    // Check supplier mismatch
    if (fs.existsSync(API_KEY_PATH)) {
      try {
        const apiKey = fs.readFileSync(API_KEY_PATH, "utf-8").trim();
        const apiPayload = JSON.parse(Buffer.from(apiKey.split(".")[1], "base64").toString());
        const apiOid = String(apiPayload.oid || "");
        const tokenSid = String(tokens.supplierId || "");
        if (apiOid && tokenSid && apiOid !== tokenSid) {
          result.error = `Несовпадение юрлиц! API-ключ: ${apiOid}, токен авторизации: ${tokenSid}. Переавторизуйтесь с правильным номером.`;
          log(`  ⚠️ SUPPLIER MISMATCH: API=${apiOid} vs Token=${tokenSid}`);
          return result;
        }
      } catch {}
    }

    // Refresh wb-seller-lk
    const refreshRes = await fetch("https://seller.wildberries.ru/ns/suppliers-auth/suppliers-portal-core/auth/token", {
      method: "POST",
      headers: { "content-type": "application/json", authorizev3: tokens.authorizev3, cookie: tokens.cookies, origin: "https://seller.wildberries.ru", referer: "https://seller.wildberries.ru/" },
      body: JSON.stringify({ params: {}, jsonrpc: "2.0", id: "json-rpc_1" }),
    });
    if (!refreshRes.ok) { result.error = "Token refresh: " + refreshRes.status; return result; }
    const sellerLk = (await refreshRes.json()).result?.data?.token;
    if (!sellerLk) { result.error = "Нет wb-seller-lk"; return result; }

    const hdrs = { authorizev3: tokens.authorizev3, "wb-seller-lk": sellerLk, cookie: tokens.cookies, origin: "https://seller.wildberries.ru", referer: "https://seller.wildberries.ru/" };

    // Get daily reports list
    const listRes = await fetch("https://seller-services.wildberries.ru/ns/reports/seller-wb-balance/api/v1/reports?limit=10&skip=0&type=6", { headers: hdrs });
    if (!listRes.ok) { result.error = "Список отчётов: " + listRes.status; return result; }
    const reports = (await listRes.json()).data?.reports || [];
    const dateReports = reports.filter(r => r.dateFrom?.slice(0, 10) === date);
    if (dateReports.length === 0) { result.error = `Отчёт за ${date} ещё не сформирован`; return result; }

    const db = new Database(DB_PATH);
    const XLSX = require("xlsx");
    const AdmZip = require("adm-zip");
    let totalRows = 0;

    for (const report of dateReports) {
      // Skip if already imported
      const existing = db.prepare("SELECT COUNT(*) as cnt FROM realization WHERE realizationreport_id = ?").get(report.id);
      if (existing.cnt > 0) { totalRows += existing.cnt; continue; }

      // Download
      const dlRes = await fetch(`https://seller-services.wildberries.ru/ns/reports/seller-wb-balance/api/v1/reports/${report.id}/details/archived-excel?format=binary`, { headers: hdrs });
      if (!dlRes.ok) { log(`Download ${report.id}: ${dlRes.status}`); continue; }

      const buf = Buffer.from(await dlRes.arrayBuffer());
      const zipPath = path.join(REPORTS_DIR, `report-${report.id}.zip`);
      fs.writeFileSync(zipPath, buf);

      // Extract
      const xlsxPath = path.join(EXTRACT_DIR, `report_${report.id}.xlsx`);
      try {
        const zip = new AdmZip(zipPath);
        for (const entry of zip.getEntries()) {
          if (entry.entryName.endsWith(".xlsx")) { fs.writeFileSync(xlsxPath, entry.getData()); break; }
        }
      } catch (e) { log(`Extract ${report.id}: ${e.message}`); continue; }
      if (!fs.existsSync(xlsxPath)) continue;

      // Parse
      const xlsxBuffer = fs.readFileSync(xlsxPath);
      const wb = XLSX.read(xlsxBuffer, { type: "buffer" });
      const rows = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
      if (rows.length === 0) continue;

      // Import
      const xlsxHeaders = Object.keys(rows[0]);
      const mappedCols = Object.entries(COL_MAP).filter(([xlsx]) => xlsxHeaders.includes(xlsx));
      const insertCols = ["realizationreport_id", "date_from", "date_to", "rr_dt", ...mappedCols.map(([, db]) => db)];
      const stmt = db.prepare(`INSERT INTO realization (${insertCols.join(", ")}) VALUES (${insertCols.map(() => "?").join(", ")})`);

      const saleDates = rows.map(r => r["Дата продажи"]).filter(Boolean).sort();
      const dateFrom = saleDates[0] || date;
      const dateTo = saleDates[saleDates.length - 1] || date;

      db.transaction(() => {
        for (const row of rows) {
          const values = [report.id, dateFrom, dateTo, dateTo];
          for (const [xlsx] of mappedCols) values.push(row[xlsx] ?? "");
          stmt.run(...values);
        }
      })();

      totalRows += rows.length;
      try { fs.unlinkSync(zipPath); } catch {}
      try { fs.unlinkSync(xlsxPath); } catch {}
    }

    db.close();
    const MIN_ROWS = 500;
    result.ok = totalRows >= MIN_ROWS;
    result.value = totalRows;
    result.stable = totalRows >= MIN_ROWS;
    if (totalRows === 0) result.error = "0 строк";
    else if (totalRows < MIN_ROWS) {
      result.error = `Отчёт неполный: ${totalRows} строк (ожидается ${MIN_ROWS}+). WB ещё не сформировал.`;
      log(`  ⚠️ Report incomplete: ${totalRows} rows < ${MIN_ROWS}`);
    }
  } catch (err) {
    result.error = err.message || String(err);
  }
  return result;
}

// --- Source 2: Advertising ---

async function syncAdvertising(date) {
  const result = { ok: false, value: 0, stable: true, prevValue: 0, lastAttempt: new Date().toISOString(), error: undefined };
  const apiKey = getApiKey();
  if (!apiKey) { result.error = "Нет WB API ключа"; return result; }

  try {
    const res = await fetch(`https://advert-api.wildberries.ru/adv/v1/upd?from=${date}&to=${date}`, {
      headers: { Authorization: apiKey },
    });
    if (!res.ok) { result.error = `API: ${res.status}`; return result; }

    const data = await res.json();
    const entries = data.filter(d => (d.updSum || 0) > 0);
    const total = entries.reduce((s, d) => s + (d.updSum || 0), 0);
    if (total === 0) { result.error = "Нет расходов"; return result; }

    const db = new Database(DB_PATH);
    db.prepare("DELETE FROM advertising WHERE date = ?").run(date);
    const ins = db.prepare("INSERT INTO advertising (date, campaign_name, campaign_id, amount, payment_type) VALUES (?, ?, ?, ?, ?)");
    db.transaction(() => {
      for (const e of entries) ins.run(date, e.campName || "", e.advertId || 0, e.updSum || 0, e.paymentType || "Баланс");
    })();
    db.close();

    result.ok = true;
    result.value = total;
  } catch (err) {
    result.error = err.message || String(err);
  }
  return result;
}

// --- Source 3: Orders ---

async function syncOrders(date, prevValue) {
  const result = { ok: false, value: 0, stable: false, prevValue: prevValue || 0, lastAttempt: new Date().toISOString(), error: undefined };
  const apiKey = getApiKey();
  if (!apiKey) { result.error = "Нет WB API ключа"; return result; }

  try {
    const res = await fetch("https://seller-analytics-api.wildberries.ru/api/analytics/v3/sales-funnel/grouped/history", {
      method: "POST",
      headers: { Authorization: apiKey, "Content-Type": "application/json" },
      body: JSON.stringify({ brandNames: [], subjectIds: [], tagIds: [], selectedPeriod: { start: date, end: date }, aggregationLevel: "day" }),
    });
    if (!res.ok) { result.error = `API: ${res.status}`; return result; }

    const data = await res.json();
    const day = data?.data?.[0]?.history?.find(h => h.date === date);
    if (!day || day.orderSum === 0) { result.error = "Нет заказов"; return result; }

    const db = new Database(DB_PATH);
    db.prepare("INSERT OR REPLACE INTO orders_funnel (date, order_sum, order_count, buyout_sum, buyout_count) VALUES (?, ?, ?, ?, ?)")
      .run(date, day.orderSum, day.orderCount, day.buyoutSum || 0, day.buyoutCount || 0);
    db.close();

    result.ok = true;
    result.value = day.orderSum;
    result.stable = prevValue > 0 && day.orderSum === prevValue;
  } catch (err) {
    result.error = err.message || String(err);
  }
  return result;
}

// --- Source 4: Weekly realization report (final, via API key) ---

async function syncWeeklyReport() {
  const apiKey = getApiKey();
  if (!apiKey) { log("  Weekly: нет API ключа, пропуск"); return; }

  // Determine last Monday-Sunday period
  const now = new Date();
  const msk = new Date(now.getTime() + 3 * 60 * 60 * 1000);
  const dayOfWeek = msk.getDay(); // 0=Sun, 1=Mon
  // Last Monday = today - (dayOfWeek === 0 ? 6 : dayOfWeek - 1) - 7
  const daysToLastMonday = (dayOfWeek === 0 ? 6 : dayOfWeek - 1) + 7;
  const lastMonday = new Date(msk);
  lastMonday.setDate(msk.getDate() - daysToLastMonday);
  const lastSunday = new Date(lastMonday);
  lastSunday.setDate(lastMonday.getDate() + 6);

  const fmtDate = (d) => d.toISOString().slice(0, 10);
  const dateFrom = fmtDate(lastMonday);
  const dateTo = fmtDate(lastSunday);

  // Check if already loaded for this period
  const db = new Database(DB_PATH);
  const existing = db.prepare(
    "SELECT COUNT(*) as cnt FROM realization WHERE source = 'weekly_final' AND sale_dt >= ? AND sale_dt <= ?"
  ).get(dateFrom, dateTo);
  if (existing.cnt > 0) {
    log(`  Weekly ${dateFrom}—${dateTo}: already loaded (${existing.cnt} rows), skipping`);
    db.close();
    return;
  }

  log(`  Weekly report ${dateFrom} — ${dateTo}...`);

  try {
    // Fetch from WB API (may need multiple pages via rrdid)
    let allRows = [];
    let rrdid = 0;
    let page = 0;

    while (true) {
      page++;
      const url = `https://statistics-api.wildberries.ru/api/v5/supplier/reportDetailByPeriod?dateFrom=${dateFrom}&dateTo=${dateTo}&rrdid=${rrdid}&limit=100000`;
      const res = await fetch(url, { headers: { Authorization: apiKey } });
      if (!res.ok) {
        log(`  Weekly API error: ${res.status}`);
        break;
      }
      const data = await res.json();
      if (!data || data.length === 0) break;
      allRows = allRows.concat(data);
      rrdid = data[data.length - 1].rrd_id || 0;
      log(`  Page ${page}: +${data.length} rows (total: ${allRows.length})`);
      if (data.length < 100000) break;
    }

    if (allRows.length === 0) {
      log(`  Weekly: отчёт за ${dateFrom}—${dateTo} пуст или ещё не готов`);
      db.close();
      return;
    }

    // НЕ удаляем daily — оставляем для сверки на вкладке «Сверка»
    // daily данные нужны как третий столбец: "7 дней ежедневный"
    const dailyCount = db.prepare(
      "SELECT COUNT(*) as cnt FROM realization WHERE source = 'daily' AND sale_dt >= ? AND sale_dt <= ?"
    ).get(dateFrom, dateTo);
    if (dailyCount.cnt > 0) {
      log(`  Daily за ${dateFrom}—${dateTo}: ${dailyCount.cnt} записей сохранены для сверки`);
    }

    // Insert final rows (38 columns, matching realization table minus auto-id)
    const cols = [
      "rrd_id", "realizationreport_id", "date_from", "date_to", "rr_dt", "sale_dt", "order_dt",
      "supplier_oper_name", "nm_id", "sa_name", "ts_name", "barcode", "brand_name", "subject_name",
      "quantity", "retail_price", "retail_price_withdisc_rub", "retail_amount",
      "ppvz_for_pay", "ppvz_sales_commission", "acquiring_fee", "delivery_rub",
      "delivery_amount", "return_amount", "storage_fee", "penalty", "acceptance",
      "rebill_logistic_cost", "additional_payment", "commission_percent",
      "ppvz_spp_prc", "ppvz_kvw_prc_base", "ppvz_kvw_prc", "ppvz_supplier_name",
      "site_country", "office_name", "deduction", "bonus_type_name", "source"
    ];
    const insertStmt = db.prepare(`INSERT INTO realization (${cols.join(",")}) VALUES (${cols.map(() => "?").join(",")})`);

    const tx = db.transaction(() => {
      for (const r of allRows) {
        insertStmt.run(
          r.rrd_id || 0, r.realizationreport_id || 0,
          r.date_from || "", r.date_to || "",
          (r.rr_dt || "").slice(0, 10), (r.sale_dt || "").slice(0, 10), (r.order_dt || "").slice(0, 10),
          r.supplier_oper_name || "", r.nm_id || 0, r.sa_name || "", r.ts_name || "", r.barcode || "",
          r.brand_name || "", r.subject_name || "",
          r.quantity || 0, r.retail_price || 0, r.retail_price_withdisc_rub || 0, r.retail_amount || 0,
          r.ppvz_for_pay || 0, r.ppvz_sales_commission || 0, r.acquiring_fee || 0, r.delivery_rub || 0,
          r.delivery_amount || 0, r.return_amount || 0, r.storage_fee || 0, r.penalty || 0, r.acceptance || 0,
          r.rebill_logistic_cost || 0, r.additional_payment || 0, r.commission_percent || 0,
          r.ppvz_spp_prc || 0, r.ppvz_kvw_prc_base || 0, r.ppvz_kvw_prc || 0,
          r.ppvz_supplier_name || "", r.site_country || "", r.office_name || "",
          r.deduction || 0, r.bonus_type_name || "",
          "weekly_final"
        );
      }
    });
    tx();

    log(`  Weekly: загружено ${allRows.length} строк за ${dateFrom}—${dateTo}`);
    db.close();
  } catch (err) {
    log(`  Weekly error: ${err.message}`);
    db.close();
  }
}

// --- Main ---

async function main() {
  const hour = new Date().getHours();
  if (hour < 6 || hour > 23) {
    log("Outside working hours (6-23), skipping");
    process.exit(0);
  }

  ensureDirs();
  const date = yesterday();
  const status = loadStatus();

  // Load or create day status
  let day = status.today;
  if (!day || day.date !== date) {
    day = {
      date,
      report: { ok: false, value: 0, stable: false, prevValue: 0, lastAttempt: "" },
      advertising: { ok: false, value: 0, stable: false, prevValue: 0, lastAttempt: "" },
      orders: { ok: false, value: 0, stable: false, prevValue: 0, lastAttempt: "" },
      complete: false,
    };
  }

  // Always check weekly report (even if daily is complete)
  log("  Weekly report check...");
  await syncWeeklyReport();

  // Skip daily if already complete
  if (day.complete) {
    log(`${date}: already complete, skipping`);
    process.exit(0);
  }

  log(`Syncing ${date}...`);

  if (!day.report.ok) {
    log("  Report...");
    day.report = await syncReport(date);
    log(`  Report: ${day.report.ok ? day.report.value + " rows" : "FAIL: " + day.report.error}`);
  }

  if (!day.advertising.ok) {
    log("  Advertising...");
    day.advertising = await syncAdvertising(date);
    log(`  Advertising: ${day.advertising.ok ? day.advertising.value + " руб" : "FAIL: " + day.advertising.error}`);
  }

  if (!day.orders.ok || !day.orders.stable) {
    log("  Orders...");
    day.orders = await syncOrders(date, day.orders.value);
    log(`  Orders: ${day.orders.ok ? day.orders.value + " руб" + (day.orders.stable ? " (stable)" : "") : "FAIL: " + day.orders.error}`);
  }

  day.complete = day.report.ok && day.advertising.ok && day.orders.ok && day.orders.stable;
  log(`  Complete: ${day.complete}`);

  status.today = day;
  status.lastRun = new Date().toISOString();

  const existingIdx = status.history.findIndex(h => h.date === date);
  if (existingIdx >= 0) status.history[existingIdx] = day;
  else { status.history.unshift(day); if (status.history.length > 30) status.history = status.history.slice(0, 30); }

  saveStatus(status);
  log("Done.");
}

main().catch(err => {
  log("FATAL: " + err.message);
  process.exit(1);
});

