// ─── Auto Buyout Rate (per article) ─────────────────────────

export interface ArticleBuyoutRate {
  articleWB: string;
  totalOrders: number;
  cancelledOrders: number;
  buyoutRate: number; // 0-1
}

/**
 * Рассчитывает реальный % выкупа по каждому артикулу.
 * Если заказов < minOrders — возвращает fallback (общий %).
 */
export function calcBuyoutByArticle(
  orders: OrderRecord[],
  fallbackRate: number = 0.75,
  minOrders: number = 30
): Map<string, number> {
  const stats = new Map<string, { total: number; cancelled: number }>();

  for (const o of orders) {
    const key = String(o.articleWB);
    const s = stats.get(key) || { total: 0, cancelled: 0 };
    s.total++;
    if (o.isCancel) s.cancelled++;
    stats.set(key, s);
  }

  const result = new Map<string, number>();
  for (const [articleWB, s] of stats) {
    if (s.total < minOrders) {
      result.set(articleWB, fallbackRate);
    } else {
      result.set(articleWB, (s.total - s.cancelled) / s.total);
    }
  }

  return result;
}

/**
 * Get all article buyout rates as array (for display).
 */
export function getAllBuyoutRates(
  orders: OrderRecord[],
  fallbackRate: number = 0.75,
  minOrders: number = 30
): ArticleBuyoutRate[] {
  const stats = new Map<string, { total: number; cancelled: number }>();

  for (const o of orders) {
    const key = String(o.articleWB);
    const s = stats.get(key) || { total: 0, cancelled: 0 };
    s.total++;
    if (o.isCancel) s.cancelled++;
    stats.set(key, s);
  }

  const result: ArticleBuyoutRate[] = [];
  for (const [articleWB, s] of stats) {
    result.push({
      articleWB,
      totalOrders: s.total,
      cancelledOrders: s.cancelled,
      buyoutRate: s.total < minOrders ? fallbackRate : (s.total - s.cancelled) / s.total,
    });
  }

  return result.sort((a, b) => b.totalOrders - a.totalOrders);
}

// ─── Auto Region Percentages (from real orders) ─────────────

export function calcAutoRegionPercents(
  orders: OrderRecord[],
  regions: RegionConfig[]
): AutoRegionPercent[] {
  const counts: Record<string, number> = {};
  for (const r of regions) counts[r.id] = 0;

  let total = 0;
  for (const o of orders) {
    if (o.isCancel) continue;
    const regionId = DISTRICT_TO_REGION[o.federalDistrict] || DISTRICT_TO_REGION[o.federalDistrict.split(" ")[0]] || null;
    if (regionId && counts[regionId] !== undefined) {
      counts[regionId]++;
      total++;
    }
  }

  return regions.map((r) => ({
    regionId: r.id,
    orderCount: counts[r.id] || 0,
    percentage: total > 0 ? (counts[r.id] || 0) / total : r.percentage,
  }));
}

// ─── V2: Shipment with Trend Dynamics ─────────────────────

export interface ShipmentCalculationV2 extends ShipmentCalculation {
  trend: TrendResult;
  rowsV1: ShipmentRow[];    // Original V1 rows for comparison
}

export function calculateShipmentV2(
  product: Product,
  stock: StockItem[],
  orders: OrderRecord[],
  buyoutRate: number = 0.75,
  regions?: RegionConfig[],
  override?: ProductOverride,
  loadedDays: number = 28
): ShipmentCalculationV2 {
  const regionConfigs = regions || getDefaultRegions();
  const disabledSizes = override?.disabledSizes || {};
  const activeSizes = product.sizes.filter((sc) => !disabledSizes[sc.barcode]);

  // Get product-level trend
  const barcodes = activeSizes.map((s) => s.barcode);
  const firstBw = barcodes.length > 0 ? getWeeklyOrders(orders, barcodes[0], loadedDays) : [];
  const numWeeks = firstBw.length || 1;
  const allWeekly = Array.from({ length: numWeeks }, (_, i) => ({
    week: i + 1,
    label: `Нед. ${i + 1}`,
    orders: 0,
    dateRange: "",
  }));
  for (const barcode of barcodes) {
    const bw = getWeeklyOrders(orders, barcode, loadedDays);
    for (let i = 0; i < Math.min(bw.length, numWeeks); i++) {
      allWeekly[i].orders += bw[i].orders;
      if (!allWeekly[i].dateRange && bw[i].dateRange) {
        allWeekly[i].dateRange = bw[i].dateRange;
      }
    }
  }
  const trend = calculateTrend(allWeekly, buyoutRate);

  // V1 rows (for comparison) — multiplier = 1
  const v1Rows = buildShipmentRows(product, stock, orders, buyoutRate, regionConfigs, override);

  // V2 rows (adjusted by trend multiplier)
  const rows = buildShipmentRows(product, stock, orders, buyoutRate, regionConfigs, override, trend.multiplier);

  const sortedRows = sortShipmentRows(rows);
  const sortedV1 = sortShipmentRows(v1Rows);

  return {
    product,
    buyoutRate,
    regionConfigs,
    rows: sortedRows,
    rowsV1: sortedV1,
    trend,
    totals: {
      totalOnWB: rows.reduce((s, r) => s + r.totalOnWB, 0),
      totalOrders: rows.reduce((s, r) => s + r.totalOrders30d, 0),
    },
  };
}

/**
 * trend-engine.ts — Расчёт динамики заказов и прогнозирование
 * 
 * Разбивает 30 дней заказов на 4 недели, строит линейный тренд,
 * прогнозирует следующий месяц с учётом динамики.
 */

import type { OrderRecord } from "@/types";
import { TREND } from "./constants";

export interface WeeklyData {
  week: number;       // 1-4
  label: string;      // "Нед. 1"
  orders: number;     // количество заказов
  dateRange: string;  // "01.03 – 07.03"
}

export interface TrendResult {
  weekly: WeeklyData[];
  slope: number;            // изменение заказов в неделю
  slopePercent: number;     // % изменения в неделю
  direction: "up" | "down" | "flat";
  forecast: number;         // прогноз на неделю 5
  forecastMonth: number;    // прогноз на месяц (4 недели вперёд)
  totalRaw: number;         // сырые заказы за 30 дней (V1)
  multiplier: number;       // forecastMonth / totalRaw
  r2: number;               // коэффициент детерминации (0-1)
  confidence: "high" | "medium" | "low";
}

/** Format local date as YYYY-MM-DD (no UTC shift) */
function toLocalISO(d: Date): string {
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
}


/**
 * Разбивает заказы по баркоду на недели по 7 дней.
 * Количество недель определяется из loadedDays (передаётся параметром).
 * Период: [сегодня − loadedDays .. сегодня] включительно.
 */
export function getWeeklyOrders(
  orders: OrderRecord[],
  barcode: string,
  loadedDays: number = 28
): WeeklyData[] {
  // Фильтр: только этот баркод (все заказы, включая отменённые)
  const filtered = orders.filter(
    (o) => o.barcode === barcode
  );

  const numWeeks = Math.max(1, Math.floor(loadedDays / 7));

  // Начало периода = сегодня - loadedDays (сегодня — неполный день, не учитываем)
  const now = new Date();
  const firstDate = new Date(now.getFullYear(), now.getMonth(), now.getDate() - loadedDays);

  const fmtDate = (d: Date) =>
    `${String(d.getDate()).padStart(2, "0")}.${String(d.getMonth() + 1).padStart(2, "0")}`;

  const weeks: WeeklyData[] = [];

  // Разбиваем от самой старой даты, по 7 дней
  for (let w = 0; w < numWeeks; w++) {
    const weekStart = new Date(firstDate.getFullYear(), firstDate.getMonth(), firstDate.getDate() + w * 7);
    const weekEnd = new Date(firstDate.getFullYear(), firstDate.getMonth(), firstDate.getDate() + (w + 1) * 7);

    // Локальное форматирование — без UTC-сдвига
    const startStr = toLocalISO(weekStart);
    const endStr = toLocalISO(weekEnd);

    const count = filtered.filter((o) => {
      const d = o.date.substring(0, 10);
      return d >= startStr && d < endStr;
    }).length;

    weeks.push({
      week: w + 1,
      label: `Нед. ${w + 1}`,
      orders: count,
      dateRange: `${fmtDate(weekStart)} – ${fmtDate(new Date(weekEnd.getFullYear(), weekEnd.getMonth(), weekEnd.getDate() - 1))}`,
    });
  }

  return weeks;
}

/**
 * Линейная регрессия y = a + b*x
 * x = номер недели (1..4), y = заказы
 */
function linearRegression(points: { x: number; y: number }[]): {
  a: number;
  b: number;
  r2: number;
} {
  const n = points.length;
  if (n < 2) return { a: 0, b: 0, r2: 0 };

  let sumX = 0, sumY = 0, sumXY = 0, sumX2 = 0, sumY2 = 0;
  for (const p of points) {
    sumX += p.x;
    sumY += p.y;
    sumXY += p.x * p.y;
    sumX2 += p.x * p.x;
    sumY2 += p.y * p.y;
  }

  const denom = n * sumX2 - sumX * sumX;
  if (denom === 0) return { a: sumY / n, b: 0, r2: 0 };

  const b = (n * sumXY - sumX * sumY) / denom;
  const a = (sumY - b * sumX) / n;

  // R² coefficient
  const yMean = sumY / n;
  let ssTot = 0, ssRes = 0;
  for (const p of points) {
    ssTot += (p.y - yMean) ** 2;
    ssRes += (p.y - (a + b * p.x)) ** 2;
  }
  const r2 = ssTot === 0 ? 0 : 1 - ssRes / ssTot;

  return { a, b, r2 };
}

/**
 * Рассчитать тренд и прогноз
 */
export function calculateTrend(weekly: WeeklyData[], buyoutRate: number = 1): TrendResult {
  const numWeeks = weekly.length;
  const totalRaw = weekly.reduce((s, w) => s + w.orders, 0);

  // Фильтруем нулевые недели (out of stock / аномалия)
  const nonZero = weekly.filter((w) => w.orders > 0);

  // Если меньше 2 недель с данными — тренд не считаем
  if (nonZero.length < 2) {
    return {
      weekly,
      slope: 0,
      slopePercent: 0,
      direction: "flat",
      forecast: totalRaw / numWeeks,
      forecastMonth: totalRaw,
      totalRaw,
      multiplier: 1,
      r2: 0,
      confidence: "low",
    };
  }

  const points = nonZero.map((w) => ({ x: w.week, y: w.orders }));
  const { a, b, r2 } = linearRegression(points);

  // Прогноз на следующую неделю (N+1)
  const forecastNext = Math.max(0, a + b * (numWeeks + 1));

  // Прогноз на следующие N недель (такой же период как загруженный)
  const forecastWeeks: number[] = [];
  for (let i = 1; i <= numWeeks; i++) {
    forecastWeeks.push(Math.max(0, a + b * (numWeeks + i)));
  }
  const forecastPeriod = forecastWeeks.reduce((s, v) => s + v, 0);

  // Последние 4 недели (для сравнения и множителя)
  const last4 = weekly.slice(-4);
  const last4Total = last4.reduce((s, w) => s + w.orders, 0);
  // Прогноз на следующие 4 недели
  const lastWeekNum = numWeeks;
  const forecast4 = [1, 2, 3, 4].reduce((s, i) => s + Math.max(0, a + b * (lastWeekNum + i)), 0);

  // Среднее значение за все недели
  const avgWeekly = totalRaw / numWeeks;

  // Slope percent
  const slopePercent = avgWeekly > 0 ? (b / avgWeekly) * 100 : 0;

  // Direction
  const pct = TREND.DIRECTION_THRESHOLD * 100;
  let direction: "up" | "down" | "flat" = "flat";
  if (slopePercent > pct) direction = "up";
  else if (slopePercent < -pct) direction = "down";

  // Confidence
  let confidence: "high" | "medium" | "low" = "low";
  if (r2 > TREND.R2_HIGH) confidence = "high";
  else if (r2 > TREND.R2_MEDIUM) confidence = "medium";

  // Multiplier: сравниваем прогноз следующей 1 недели со средней неделей
  // Прогнозируем на 1 неделю вперёд, а не на 4 — данные обновляются еженедельно
  const avgWeekLast4 = last4Total / last4.length;
  const multiplier = avgWeekLast4 > 0 ? forecastNext / avgWeekLast4 : 1;

  return {
    weekly,
    slope: b,
    slopePercent,
    direction,
    forecast: forecastNext,
    forecastMonth: forecastPeriod,
    totalRaw,
    multiplier: Math.max(TREND.MULTIPLIER_MIN, Math.min(TREND.MULTIPLIER_MAX, multiplier)),
    r2,
    confidence,
  };
}

/**
 * Получить тренд для всех баркодов товара
 */
export function getProductTrend(
  orders: OrderRecord[],
  barcodes: string[],
  buyoutRate: number = 0.75,
  loadedDays: number = 28
): TrendResult {
  // Объединяем все заказы по всем баркодам товара
  // Определяем количество недель из первого баркода
  const firstBw = barcodes.length > 0 ? getWeeklyOrders(orders, barcodes[0], loadedDays) : [];
  const numWeeks = firstBw.length || 1;

  const allWeekly: WeeklyData[] = Array.from({ length: numWeeks }, (_, i) => ({
    week: i + 1,
    label: `Нед. ${i + 1}`,
    orders: 0,
    dateRange: "",
  }));

  for (const barcode of barcodes) {
    const bw = getWeeklyOrders(orders, barcode, loadedDays);
    for (let i = 0; i < Math.min(bw.length, numWeeks); i++) {
      allWeekly[i].orders += bw[i].orders;
      if (!allWeekly[i].dateRange && bw[i].dateRange) {
        allWeekly[i].dateRange = bw[i].dateRange;
      }
    }
  }

  return calculateTrend(allWeekly, buyoutRate);
}

/**
 * Auth utilities — password hashing + JWT-like tokens.
 * Uses Node.js built-in crypto only (no external deps).
 */

import crypto from "crypto";

const JWT_SECRET = process.env.JWT_SECRET || "mphub-dev-secret-2026";
if (!process.env.JWT_SECRET && process.env.NODE_ENV === "production") {
  console.warn("[AUTH] WARNING: JWT_SECRET not set — using insecure default. Set JWT_SECRET env variable!");
}
import { AUTH } from "./constants";

const TOKEN_TTL = AUTH.TOKEN_TTL_SECONDS;

// --- Password hashing ---

/** Returns "salt:hash" where hash = sha256(salt + password) */
export function hashPassword(password: string): string {
  const salt = crypto.randomBytes(16).toString("hex");
  const hash = crypto.createHash("sha256").update(salt + password).digest("hex");
  return `${salt}:${hash}`;
}

/** Verifies password against stored "salt:hash" */
export function verifyPassword(password: string, storedHash: string): boolean {
  const [salt, hash] = storedHash.split(":");
  if (!salt || !hash) return false;
  const computed = crypto.createHash("sha256").update(salt + password).digest("hex");
  return crypto.timingSafeEqual(Buffer.from(computed, "hex"), Buffer.from(hash, "hex"));
}

// --- Token (custom JWT-like: base64url(header).base64url(payload).hmac-sha256) ---

interface TokenPayload {
  userId: number;
  iat: number;
  exp: number;
}

function base64url(s: string): string {
  return Buffer.from(s).toString("base64url");
}

function fromBase64url(s: string): string {
  return Buffer.from(s, "base64url").toString("utf8");
}

export function createToken(userId: number): string {
  const now = Math.floor(Date.now() / 1000);
  const payload: TokenPayload = { userId, iat: now, exp: now + TOKEN_TTL };
  const header = base64url(JSON.stringify({ alg: "HS256", typ: "JWT" }));
  const body = base64url(JSON.stringify(payload));
  const sig = crypto
    .createHmac("sha256", JWT_SECRET)
    .update(`${header}.${body}`)
    .digest("base64url");
  return `${header}.${body}.${sig}`;
}

export function verifyToken(token: string): { userId: number } | null {
  try {
    const parts = token.split(".");
    if (parts.length !== 3) return null;
    const [header, body, sig] = parts;
    const expectedSig = crypto
      .createHmac("sha256", JWT_SECRET)
      .update(`${header}.${body}`)
      .digest("base64url");
    // Constant-time compare
    if (sig.length !== expectedSig.length) return null;
    if (!crypto.timingSafeEqual(Buffer.from(sig), Buffer.from(expectedSig))) return null;
    const payload: TokenPayload = JSON.parse(fromBase64url(body));
    const now = Math.floor(Date.now() / 1000);
    if (payload.exp < now) return null;
    return { userId: payload.userId };
  } catch {
    return null;
  }
}

