  { key: "logistics",  label: "Логист./шт",      dayFn: () => "",                                       artFn: a => RUB(a.logistics_unit),   defaultOn: false },
  { key: "commission", label: "Комисс./шт",      dayFn: () => "",                                       artFn: a => RUB(a.commission_unit),  defaultOn: false },
  { key: "tax",        label: "Налоги/шт",       dayFn: () => "",                                       artFn: a => RUB(a.tax_unit),         defaultOn: false },
  { key: "ppu",        label: "Прибыль/шт",      dayFn: () => "",                                       artFn: a => RUB(a.profit_per_unit),  defaultOn: true },
  { key: "storage",    label: "Хранение",        dayFn: d => RUB(d.storage),                            artFn: a => a.storage ? RUB(a.storage) : "—", defaultOn: true },
  { key: "penalties",  label: "Штрафы",          dayFn: d => d.penalties ? RUB(d.penalties) : "—",       artFn: a => a.penalties ? RUB(a.penalties) : "—", defaultOn: false },
  { key: "ad_spend",   label: "Реклама",         dayFn: d => RUB(d.ad_spend),                           artFn: a => a.ad_spend ? RUB(a.ad_spend) : "—", defaultOn: true },
  { key: "profit_ba",  label: "До рекламы",      dayFn: d => RUB(d.estimated_profit_before_ads),        artFn: () => "",                     defaultOn: false },
  { key: "est_profit", label: "Прогн. прибыль",  dayFn: d => RUB(d.estimated_profit),                   artFn: a => RUB(a.estimated_profit), defaultOn: true },
  { key: "running",    label: "Нарастающая",     dayFn: d => RUB(d.running_profit),                     artFn: () => "",                     defaultOn: true },
];

export default function ForecastTab({ dateFrom, dateTo }: { dateFrom: string; dateTo: string }) {
  const [data, setData] = useState<ForecastDay[]>([]);
  const [loading, setLoading] = useState(true);
  const [expandedDay, setExpandedDay] = useState<string | null>(null);
  const [meta, setMeta] = useState<{ econFrom: string; econTo: string; econDays: number; articlesCount: number } | null>(null);
  const [visibleCols, setVisibleCols] = useState<Set<string>>(() => new Set(COLUMNS.filter(c => c.defaultOn).map(c => c.key)));
  const [showSettings, setShowSettings] = useState(false);

  useEffect(() => {
    if (!dateFrom || !dateTo) return;
    setLoading(true);
    fetch(`/api/finance/forecast?from=${dateFrom}&to=${dateTo}`)
      .then(r => r.json())
      .then(resp => {
        setData(Array.isArray(resp?.days) ? resp.days : (Array.isArray(resp) ? resp : []));
        if (resp?.meta) setMeta(resp.meta);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, [dateFrom, dateTo]);

  if (loading) {
    return <div className="text-center py-12 text-[var(--text-muted)]">Расчёт прогноза...</div>;
  }

  if (!data.length) {
    return (
      <div className="bg-[var(--bg-card)] rounded-xl border border-[var(--border)] p-8 text-center">
        <p className="text-xl font-medium">Нет данных для прогноза</p>
        <p className="text-sm text-[var(--text-muted)] mt-2">Нужны заказы в таблице shipment_orders</p>
      </div>
    );
  }

  const totalOrders = data.reduce((s, d) => s + d.orders, 0);
  const totalRevenue = data.reduce((s, d) => s + d.estimated_revenue, 0);
  const totalAds = data.reduce((s, d) => s + d.ad_spend, 0);
  const totalProfit = data.reduce((s, d) => s + d.estimated_profit, 0);
  const totalProfitBeforeAds = data.reduce((s, d) => s + d.estimated_profit_before_ads, 0);
  const fmtM = (v: number) => { if (Math.abs(v) >= 1e6) return (v / 1e6).toFixed(1) + "M"; if (Math.abs(v) >= 1e3) return Math.round(v / 1e3) + "k"; return String(v); };

  const chartData = data.map(d => ({
    date: fmtDate(d.date),
    profit: d.estimated_profit,
    ads: d.ad_spend,
    running_profit: d.running_profit,
    running_revenue: d.running_revenue,
  }));

  const cols = COLUMNS.filter(c => visibleCols.has(c.key));

  const toggleCol = (key: string) => {
    setVisibleCols(prev => {
      const next = new Set(prev);
      next.has(key) ? next.delete(key) : next.add(key);
      return next;
    });
  };

  return (
    <div className="space-y-6">
      {/* Description */}
      <div className="bg-[var(--bg-card)] rounded-xl border border-[var(--border)] px-4 py-3">
        <p className="text-xs text-[var(--text-muted)]">
          Прогноз прибыли: <strong className="text-[var(--text)]">заказы × % выкупа × прибыль/шт − реклама − хранение − штрафы</strong>.
          {meta && <> Юнит-экономика за <strong className="text-[var(--text)]">{fmtDate(meta.econFrom)} — {fmtDate(meta.econTo)}</strong> ({meta.articlesCount} артикулов). % выкупа — исторический.</>}
        </p>
      </div>

      {/* Summary cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        <div className="bg-[var(--bg-card)] rounded-xl border border-[var(--border)] p-4">
          <p className="text-xs text-[var(--text-muted)] uppercase">Заказов</p>
          <p className="text-2xl font-bold text-white mt-1">{formatNumber(totalOrders)} шт</p>
        </div>
        <div className="bg-[var(--bg-card)] rounded-xl border border-[var(--border)] p-4">
          <p className="text-xs text-[var(--text-muted)] uppercase">Прогноз выручки</p>
          <p className="text-2xl font-bold text-white mt-1">{RUB(totalRevenue)}</p>
        </div>
        <div className="bg-[var(--bg-card)] rounded-xl border border-[var(--border)] p-4">
          <p className="text-xs text-[var(--text-muted)] uppercase">Реклама</p>
          <p className="text-2xl font-bold text-[var(--warning)] mt-1">{RUB(totalAds)}</p>
        </div>
        <div className="bg-[var(--bg-card)] rounded-xl border border-[var(--border)] p-4">
          <p className="text-xs text-[var(--text-muted)] uppercase">Прогноз прибыли</p>
          <p className={`text-2xl font-bold mt-1 ${totalProfit >= 0 ? "text-[var(--success)]" : "text-[var(--danger)]"}`}>{RUB(totalProfit)}</p>
          <p className="text-xs text-[var(--text-muted)] mt-1">без рекламы: {RUB(totalProfitBeforeAds)}</p>
        </div>
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <div className="bg-[var(--bg-card)] rounded-xl border border-[var(--border)] p-5">
          <h3 className="text-sm font-medium text-[var(--text-muted)] uppercase tracking-wide mb-4">Прибыль и реклама по дням</h3>
          <ResponsiveContainer width="100%" height={240}>
            <BarChart data={chartData} margin={{ top: 5, right: 10, left: 10, bottom: 5 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#2a2a3a" />
              <XAxis dataKey="date" tick={{ fill: "#8888a0", fontSize: 10 }} />
              <YAxis tickFormatter={fmtM} tick={{ fill: "#8888a0", fontSize: 11 }} />
              <Tooltip contentStyle={{ background: "#12121a", border: "1px solid #2a2a3a", borderRadius: 8, color: "#e4e4ef" }} formatter={(v: unknown) => RUB(Number(v))} />
              <Legend wrapperStyle={{ color: "#8888a0", fontSize: 12 }} />
              <Bar dataKey="profit" name="Прибыль" fill="#66BB6A" radius={[4, 4, 0, 0]} />
              <Bar dataKey="ads" name="Реклама" fill="#F4A236" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
        <div className="bg-[var(--bg-card)] rounded-xl border border-[var(--border)] p-5">
          <h3 className="text-sm font-medium text-[var(--text-muted)] uppercase tracking-wide mb-4">Нарастающая: выручка vs прибыль</h3>
          <ResponsiveContainer width="100%" height={240}>
            <LineChart data={chartData} margin={{ top: 5, right: 10, left: 10, bottom: 5 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#2a2a3a" />
              <XAxis dataKey="date" tick={{ fill: "#8888a0", fontSize: 10 }} />
              <YAxis tickFormatter={fmtM} tick={{ fill: "#8888a0", fontSize: 11 }} />
              <Tooltip contentStyle={{ background: "#12121a", border: "1px solid #2a2a3a", borderRadius: 8, color: "#e4e4ef" }} formatter={(v: unknown) => RUB(Number(v))} />
              <Legend />
              <Line type="monotone" dataKey="running_revenue" name="Выручка" stroke="var(--success)" strokeWidth={2} dot={false} />
              <Line type="monotone" dataKey="running_profit" name="Прибыль" stroke="var(--accent)" strokeWidth={2} dot={false} strokeDasharray="6 3" />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Table */}
      <div className="bg-[var(--bg-card)] rounded-xl border border-[var(--border)] p-5">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-sm font-medium text-[var(--text-muted)] uppercase tracking-wide">Прогноз по дням</h3>
          {/* Column settings */}
          <div className="relative">
            <button
              onClick={() => setShowSettings(!showSettings)}
              className="p-2 rounded-lg border border-[var(--border)] text-[var(--text-muted)] hover:text-white hover:border-[var(--accent)] transition-colors text-xs"
            >
              Столбцы ({cols.length}/{COLUMNS.length})
            </button>
            {showSettings && (
              <div className="absolute right-0 top-10 z-50 bg-[var(--bg-card)] border border-[var(--border)] rounded-xl p-3 shadow-xl min-w-[200px]">
                {COLUMNS.map(c => (
                  <label key={c.key} className="flex items-center gap-2 py-1 cursor-pointer text-xs">
                    <input
                      type="checkbox"
                      checked={visibleCols.has(c.key)}
                      onChange={() => toggleCol(c.key)}
                      className="rounded"
                    />
                    <span className={visibleCols.has(c.key) ? "text-white" : "text-[var(--text-muted)]"}>{c.label}</span>
                  </label>
                ))}
                <div className="border-t border-[var(--border)] mt-2 pt-2 flex gap-2">
                  <button onClick={() => setVisibleCols(new Set(COLUMNS.map(c => c.key)))} className="text-[10px] text-[var(--accent)] hover:underline">Все</button>
                  <button onClick={() => setVisibleCols(new Set(COLUMNS.filter(c => c.defaultOn).map(c => c.key)))} className="text-[10px] text-[var(--text-muted)] hover:underline">По умолчанию</button>
                </div>
              </div>
            )}
          </div>
        </div>

        <div className="data-table-wrapper">
          <table className="data-table">
            <thead>
              <tr>
                <th>Дата</th>
                {cols.map(c => <th key={c.key} className="num">{c.label}</th>)}
              </tr>
            </thead>
            <tbody>
              {[...data].reverse().map(row => (
                <>
                  <tr
                    key={row.date}
                    className="cursor-pointer hover:bg-[var(--bg-card-hover)]"
                    onClick={() => setExpandedDay(expandedDay === row.date ? null : row.date)}
                  >
                    <td className="font-mono text-[var(--text-muted)]">
                      {expandedDay === row.date ? "▾" : "▸"} {fmtDate(row.date)}
                    </td>
                    {cols.map(c => {
                      const val = c.dayFn(row);
                      const isProfit = c.key === "est_profit";
                      return (
                        <td key={c.key} className={`num ${isProfit ? (row.estimated_profit >= 0 ? "cell-positive" : "cell-negative") : ""} ${c.key === "running" ? "text-[var(--accent)]" : ""}`}>
                          {val || "—"}
                        </td>
                      );
                    })}
                  </tr>
                  {expandedDay === row.date && row.articles.map(art => (
                    <tr key={`${row.date}-${art.nm_id}`} className="bg-[var(--bg)]/50 text-xs">
                      <td className="pl-6">
                        <span className="text-[var(--text-muted)]">{art.nm_id}</span>
                        <span className="ml-2 text-[var(--text-muted)] opacity-60">{art.article}</span>
                        {art.custom_name && <span className="ml-2 text-white font-medium">{art.custom_name}</span>}
                      </td>
                      {cols.map(c => {
                        const val = c.artFn?.(art) || "";
                        const isProfit = c.key === "est_profit";
                        return (
                          <td key={c.key} className={`num ${isProfit ? (art.estimated_profit >= 0 ? "cell-positive" : "cell-negative") : ""}`}>
                            {val || "—"}
                          </td>
                        );
                      })}
                    </tr>
                  ))}
                </>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";

interface WeekMetrics {
  salesQty: number;
  returnsQty: number;
  sales: number;
  returns: number;
  ppvz: number;
  ppvzReturns: number;
  logistics: number;
  deliveryCount: number;
  returnCount: number;
  storage: number;
  penalties: number;
  acceptance: number;
  deductions: number;
  rebill: number;
  acquiring: number;
  compensation: number;
  corrections: number;
}

interface WeekData {
  dateFrom: string;
  dateTo: string;
  status: "final" | "preliminary";
  apiWeekly: WeekMetrics;
  excelLk: WeekMetrics;
  hasExcel: boolean;
}

interface ReconciliationResponse {
  weeks: WeekData[];
  totalApi: WeekMetrics;
  totalExcel: WeekMetrics;
}

const RUB = (n: number) =>
  n.toLocaleString("ru-RU", { maximumFractionDigits: 0 }) + " ₽";
const QTY = (n: number) => n.toLocaleString("ru-RU");
const fmtDate = (d: string) => (d ? `${d.slice(8)}.${d.slice(5, 7)}` : "");

function DiffBadge({ a, b, isQty }: { a: number; b: number; isQty?: boolean }) {
  if (b === 0 && a === 0) return <span className="text-[var(--text-muted)]">—</span>;
  if (b === 0) return <span className="text-[var(--text-muted)]">н/д</span>;
  const diff = a - b;
  const pct = Math.abs(b) > 0 ? ((diff / Math.abs(b)) * 100) : 0;
  const ok = Math.abs(pct) < 1;
  const fmt = isQty ? String(diff) : (diff >= 0 ? "+" : "") + RUB(diff);
  return (
    <span className={`text-xs font-medium ${ok ? "text-[var(--success)]" : "text-[var(--danger)]"}`}>
      {Math.abs(diff) <= 1 ? "✅" : `${fmt} (${pct.toFixed(1)}%)`}
    </span>
  );
}

const metrics: { key: keyof WeekMetrics; label: string; isQty?: boolean }[] = [
  { key: "salesQty", label: "Кол-во продаж", isQty: true },
  { key: "returnsQty", label: "Кол-во возвратов", isQty: true },
  { key: "sales", label: "Цена розничная с учётом согласованной скидки (продажи)" },
  { key: "returns", label: "Цена розничная с учётом согласованной скидки (возвраты)" },
  { key: "ppvz", label: "К перечислению Продавцу за реализованный Товар (продажи)" },
  { key: "ppvzReturns", label: "К перечислению Продавцу за реализованный Товар (возвраты)" },
  { key: "logistics", label: "Услуги по доставке товара покупателю" },
  { key: "deliveryCount", label: "Количество доставок", isQty: true },
  { key: "returnCount", label: "Количество возвратов (доставка)", isQty: true },
  { key: "storage", label: "Хранение" },
  { key: "penalties", label: "Общая сумма штрафов" },
  { key: "acceptance", label: "Операции на приёмке" },
  { key: "deductions", label: "Удержания (WB Продвижение)" },
  { key: "rebill", label: "Возмещение издержек по перевозке" },
  { key: "acquiring", label: "Эквайринг / Комиссии за организацию платежей" },
  { key: "compensation", label: "Компенсация скидки по программе лояльности" },
  { key: "corrections", label: "Корректировки (прочие статьи)" },
];

function TotalRow({ label, api, excel, hasExcel }: { label: string; api: WeekMetrics; excel: WeekMetrics; hasExcel: boolean }) {
  const moneyMetrics = metrics.filter((m) => !m.isQty);
  const totalApi = moneyMetrics.reduce((sum, m) => sum + api[m.key], 0);
  const totalExcel = moneyMetrics.reduce((sum, m) => sum + excel[m.key], 0);
  const diff = totalApi - totalExcel;
  const pct = Math.abs(totalExcel) > 0 ? (Math.abs(diff) / Math.abs(totalExcel)) * 100 : 0;
  const diffColor = pct < 1 ? "text-[var(--success)]" : pct < 5 ? "text-[var(--warning)]" : "text-[var(--danger)]";

  return (
    <tr style={{ borderTop: "2px solid var(--border)" }} className="font-bold bg-orange-500/15">
      <td className="text-sm py-3 text-orange-400">{label}</td>
      <td className="num py-3">{RUB(totalApi)}</td>
      <td className="num py-3">
        {hasExcel ? RUB(totalExcel) : <span className="text-[var(--text-muted)]">—</span>}
      </td>
      <td className="num py-3">
        {hasExcel ? (
          <span className={`text-xs font-bold ${diffColor}`}>
            {Math.abs(diff) <= 1 ? "✅" : `${diff >= 0 ? "+" : ""}${RUB(diff)} (${pct.toFixed(1)}%)`}
          </span>
        ) : (
          <span className="text-[var(--text-muted)]">—</span>
        )}
      </td>
    </tr>
  );
}

export default function ReconciliationTab() {
  const [weeks, setWeeks] = useState<WeekData[]>([]);
  const [totalApi, setTotalApi] = useState<WeekMetrics | null>(null);
  const [totalExcel, setTotalExcel] = useState<WeekMetrics | null>(null);
  const [loading, setLoading] = useState(true);
  const [selectedWeek, setSelectedWeek] = useState<WeekData | null>(null);

  useEffect(() => {
    fetch("/api/finance/reconciliation")
      .then((r) => r.json())
      .then((data: ReconciliationResponse) => {
        setWeeks(data.weeks);
        setTotalApi(data.totalApi);
        setTotalExcel(data.totalExcel);
        const firstFinal = data.weeks.find((w) => w.status === "final");
        if (firstFinal) setSelectedWeek(firstFinal);
        else if (data.weeks.length > 0) setSelectedWeek(data.weeks[0]);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, []);

  if (loading) {
    return (
      <div className="text-center py-12 text-[var(--text-muted)]">
        Загрузка данных сверки...
      </div>
    );
  }

  if (weeks.length === 0) {
    return (
      <div className="bg-[var(--bg-card)] rounded-xl border border-[var(--border)] p-8 text-center">
        <p className="text-xl font-medium">Нет данных для сверки</p>
        <p className="text-sm text-[var(--text-muted)] mt-2">
          Финальные еженедельные отчёты WB загрузятся автоматически
        </p>
      </div>
    );
  }

  const w = selectedWeek;
  const hasAnyExcel = weeks.some((wk) => wk.hasExcel);

  return (
    <div className="space-y-6">
      {/* Description */}
      <div className="bg-[var(--bg-card)] rounded-xl border border-[var(--border)] px-4 py-3">
        <p className="text-xs text-[var(--text-muted)]">
          Сверка сравнивает два источника данных WB: <strong className="text-[var(--text)]">API</strong> (weekly_final из finance.db) и <strong className="text-[var(--text)]">Excel</strong> (еженедельные отчёты из ЛК WB). Расхождение &lt;1% — норма.
        </p>
      </div>

      {/* Total summary across all weeks */}
      {totalApi && totalExcel && hasAnyExcel && (
        <div className="bg-[var(--bg-card)] rounded-xl border border-[var(--border)] overflow-auto">
          <div className="p-4 border-b border-[var(--border)]">
            <h3 className="text-lg font-bold">Итог по всем неделям</h3>
            <p className="text-xs text-[var(--text-muted)] mt-1">{weeks.filter(wk => wk.status === "final").length} завершённых недель</p>
          </div>
          <table className="data-table">
            <thead>
              <tr>
                <th>Метрика</th>
                <th className="num">API</th>
                <th className="num">Excel</th>
                <th className="num">Разница</th>
              </tr>
            </thead>
            <tbody>
              {metrics.map((m) => {
                const fmt = m.isQty ? QTY : RUB;
                const api = totalApi[m.key];
                const excel = totalExcel[m.key];
                return (
                  <tr key={m.key}>
                    <td className="font-medium text-sm">{m.label}</td>
                    <td className="num">{api ? fmt(api) : <span className="text-[var(--text-muted)]">—</span>}</td>
                    <td className="num">{excel ? fmt(excel) : <span className="text-[var(--text-muted)]">—</span>}</td>
                    <td className="num">
                      {api || excel ? <DiffBadge a={api} b={excel} isQty={m.isQty} /> : <span className="text-[var(--text-muted)]">—</span>}
                    </td>
                  </tr>
                );
              })}
              <TotalRow label="Итого" api={totalApi} excel={totalExcel} hasExcel={true} />
            </tbody>
          </table>
        </div>
      )}

      {/* Week selector */}
      <div className="flex flex-wrap gap-2">
        {weeks.map((wk) => {
          const isSelected = w?.dateFrom === wk.dateFrom;
          const isFinal = wk.status === "final";
          return (
            <button
              key={wk.dateFrom}
              onClick={() => setSelectedWeek(wk)}
              className={`px-4 py-2 rounded-lg text-sm font-medium border transition-colors ${
                isSelected
                  ? "bg-[var(--accent)]/20 text-[var(--accent)] border-[var(--accent)]"
                  : "bg-[var(--bg-card)] text-[var(--text-muted)] border-[var(--border)] hover:text-white"
              }`}
            >
              {fmtDate(wk.dateFrom)} – {fmtDate(wk.dateTo)}
              <span
                className={`ml-2 text-xs ${isFinal ? "text-[var(--success)]" : "text-[var(--warning)]"}`}
              >
                {isFinal ? "✅" : "⏳"}
              </span>
            </button>
          );
        })}
      </div>

      {/* Detail table for selected week */}
      {w && (
        <div className="bg-[var(--bg-card)] rounded-xl border border-[var(--border)] overflow-auto">
          <div className="p-4 border-b border-[var(--border)]">
            <h3 className="text-lg font-bold">
              Сверка за {fmtDate(w.dateFrom)} – {fmtDate(w.dateTo)}
            </h3>
            <div className="flex gap-4 mt-2 text-xs text-[var(--text-muted)]">
              <span>
                API:{" "}
                <span className={w.status === "final" ? "text-[var(--success)]" : "text-[var(--warning)]"}>
                  {w.status === "final" ? "✅ загружен" : "⏳ нет"}
                </span>
              </span>
              <span>
                Excel:{" "}
                <span className={w.hasExcel ? "text-[var(--success)]" : "text-[var(--text-muted)]"}>
                  {w.hasExcel ? "✅ загружен" : "— нет"}
                </span>
              </span>
            </div>
          </div>

          <table className="data-table">
            <thead>
              <tr>
                <th>Метрика</th>
                <th className="num">API</th>
                <th className="num">Excel</th>
                <th className="num">Разница</th>
              </tr>
            </thead>
            <tbody>
              {metrics.map((m) => {
                const fmt = m.isQty ? QTY : RUB;
                const api = w.apiWeekly[m.key];
                const excel = w.excelLk[m.key];

                return (
                  <tr key={m.key}>
                    <td className="font-medium text-sm">{m.label}</td>
                    <td className="num">{api ? fmt(api) : <span className="text-[var(--text-muted)]">—</span>}</td>
                    <td className="num">
                      {w.hasExcel ? fmt(excel) : <span className="text-[var(--text-muted)]">—</span>}
                    </td>
                    <td className="num">
                      {w.hasExcel && api ? (
                        <DiffBadge a={api} b={excel} isQty={m.isQty} />
                      ) : (
                        <span className="text-[var(--text-muted)]">—</span>
                      )}
                    </td>
                  </tr>
                );
              })}
              <TotalRow label="Итого (все статьи)" api={w.apiWeekly} excel={w.excelLk} hasExcel={w.hasExcel} />
            </tbody>
          </table>

          {/* Overall status */}
          {w.status === "final" && w.hasExcel && (
            <div className="p-4 border-t border-[var(--border)]">
              {(() => {
                const diffs = metrics
                  .filter((m) => !m.isQty)
                  .map((m) => ({
                    diff: Math.abs(w.apiWeekly[m.key] - w.excelLk[m.key]),
                    base: Math.abs(w.excelLk[m.key]),
                  }));
                const totalDiff = diffs.reduce((s, d) => s + d.diff, 0);
                const totalBase = diffs.reduce((s, d) => s + d.base, 0);
                const pct = totalBase > 0 ? (totalDiff / totalBase) * 100 : 0;
                const ok = pct < 1;
                return (
                  <p className={`text-sm font-medium ${ok ? "text-[var(--success)]" : "text-[var(--danger)]"}`}>
                    API vs Excel: {ok ? "✅ Сходится" : "⚠️ Расхождение"} — общая разница{" "}
                    {pct.toFixed(2)}%
                  </p>
                );
              })()}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

import { NextRequest, NextResponse } from "next/server";
import { apiError } from "@/lib/api-utils";
import { getDb } from "@/lib/db";
import { DEFAULT_COGS_PER_UNIT } from "@/lib/constants";

/**
 * GET /api/finance/forecast?from=YYYY-MM-DD&to=YYYY-MM-DD
 *
 * Прогноз прибыли: заказы × выкуп × юнит-экономика − реклама − хранение − штрафы − overhead.
 *
 * Юнит-экономика берётся за ПРЕДЫДУЩИЙ период (14 дней до dateFrom),
 * чтобы прогноз был честным — не использовал данные из будущего.
 *
 * Заказы, реклама, хранение, штрафы — за запрошенный период (dateFrom–dateTo).
 */

/** Дата минус N дней (без UTC-сдвига) */
function shiftDays(dateStr: string, days: number): string {
  const [y, m, d] = dateStr.split("-").map(Number);
  const dt = new Date(y, m - 1, d + days);
  return `${dt.getFullYear()}-${String(dt.getMonth() + 1).padStart(2, "0")}-${String(dt.getDate()).padStart(2, "0")}`;
}

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url);
  const dateFrom = searchParams.get("from") || "";
  const dateTo = searchParams.get("to") || "";
  if (!dateFrom || !dateTo) {
    return NextResponse.json({ error: "from and to required" }, { status: 400 });
  }

  try {
    const d = getDb();

    // Юнит-экономика за тот же период, что и прогноз
    // Для понедельного прогноза (вперёд) берутся предыдущие 14 дней автоматически
    const econFrom = dateFrom;
    const econTo = dateTo;

    // ── 1. Юнит-экономика по артикулам (ПРЕДЫДУЩИЙ период) ──
    const articlesRaw = d.prepare(`
      SELECT nm_id,
        SUM(CASE WHEN supplier_oper_name='Продажа' THEN retail_price_withdisc_rub ELSE 0 END) as sales_rpwd,
        SUM(CASE WHEN supplier_oper_name='Продажа' THEN ppvz_for_pay ELSE 0 END) as sales_ppvz,
        SUM(CASE WHEN supplier_oper_name='Продажа' THEN quantity ELSE 0 END) as sales_qty,
        SUM(CASE WHEN supplier_oper_name='Возврат' THEN quantity ELSE 0 END) as ret_qty
      FROM realization
      WHERE supplier_oper_name IN ('Продажа','Возврат')
        AND sale_dt >= ? AND sale_dt <= ? AND nm_id > 0
      GROUP BY nm_id
    `).all(econFrom, econTo) as Record<string, number>[];

    const logisticsRaw = d.prepare(`
      SELECT nm_id,
        SUM(CASE WHEN supplier_oper_name='Логистика' THEN delivery_rub ELSE 0 END) as logistics
      FROM realization
      WHERE rr_dt >= ? AND rr_dt <= ? AND nm_id > 0
      GROUP BY nm_id
    `).all(econFrom, econTo) as Record<string, number>[];
    const logMap = new Map(logisticsRaw.map(r => [r.nm_id, r.logistics]));

    const cogsRaw = d.prepare(`
      SELECT nm_id,
        SUM(quantity * COALESCE((SELECT cost FROM cogs WHERE cogs.barcode = r.barcode), ${DEFAULT_COGS_PER_UNIT})) as cogs_total,
        SUM(quantity) as qty
      FROM realization r
      WHERE supplier_oper_name = 'Продажа' AND sale_dt >= ? AND sale_dt <= ? AND nm_id > 0
      GROUP BY nm_id
    `).all(econFrom, econTo) as Record<string, number>[];
    const cogsMap = new Map(cogsRaw.map(r => [r.nm_id, r.qty > 0 ? r.cogs_total / r.qty : DEFAULT_COGS_PER_UNIT]));

    // Build unit economics: все составляющие прибыли на штуку
    interface UnitEcon {
      avgPrice: number; cogsUnit: number; logUnit: number;
      commissionUnit: number; taxUnit: number; profitPerUnit: number;
      article: string; customName: string;
    }
    const unitEcon = new Map<number, UnitEcon>();
    for (const a of articlesRaw) {
      const netQty = a.sales_qty - a.ret_qty;
      if (netQty <= 0) continue;
      const avgPrice = a.sales_rpwd / a.sales_qty;
      const avgPpvz = a.sales_ppvz / a.sales_qty;
      const cogsUnit = cogsMap.get(a.nm_id) || DEFAULT_COGS_PER_UNIT;
      const logUnit = (logMap.get(a.nm_id) || 0) / netQty;
      const commissionUnit = avgPrice - avgPpvz;
      const ndsUnit = avgPpvz * 5 / 105;
      const usnUnit = (avgPpvz - ndsUnit) * 0.01;
      const taxUnit = ndsUnit + usnUnit;
      const profitPerUnit = avgPrice - cogsUnit - logUnit - commissionUnit - taxUnit;
      unitEcon.set(a.nm_id, { avgPrice, cogsUnit, logUnit, commissionUnit, taxUnit, profitPerUnit, article: "", customName: "" });
    }

    // Article names (sa_name from realization)
    const names = d.prepare(`
      SELECT DISTINCT nm_id, sa_name FROM realization
      WHERE nm_id > 0 AND sa_name != '' AND sale_dt >= ? AND sale_dt <= ?
    `).all(econFrom, dateTo) as { nm_id: number; sa_name: string }[];
    for (const n of names) {
      const e = unitEcon.get(n.nm_id);
      if (e) e.article = n.sa_name;
    }

    // Custom names (из product_overrides)
    const customNames = d.prepare(`
      SELECT DISTINCT article_wb, custom_name FROM product_overrides
      WHERE custom_name IS NOT NULL AND custom_name != ''
    `).all() as { article_wb: string; custom_name: string }[];
    for (const cn of customNames) {
      const e = unitEcon.get(Number(cn.article_wb));
      if (e) e.customName = cn.custom_name;
    }

    // ── 2. Исторический % выкупа по артикулам (вся история) ──
    const buyoutRaw = d.prepare(`
      SELECT article_wb as nm_id,
        COUNT(*) as total,
        SUM(CASE WHEN is_cancel = 1 THEN 1 ELSE 0 END) as cancels
      FROM shipment_orders
      GROUP BY article_wb
    `).all() as { nm_id: number; total: number; cancels: number }[];
    const buyoutMap = new Map(buyoutRaw.map(r => [r.nm_id, r.total > 30 ? (r.total - r.cancels) / r.total : 0.80]));

    // ── 3. Заказы за прогнозируемый период ──
    const ordersDaily = d.prepare(`
      SELECT SUBSTR(date, 1, 10) as day, article_wb as nm_id,
        COUNT(*) as orders,
        SUM(price_with_disc) as orders_rub
      FROM shipment_orders
      WHERE date >= ? AND date <= ? || 'T23:59:59'
      GROUP BY day, nm_id
    `).all(dateFrom, dateTo) as { day: string; nm_id: number; orders: number; orders_rub: number }[];

    // ── 4. Реклама за прогнозируемый период (точная, по nm_id) ──
    const adsDaily = d.prepare(`
      SELECT date, nm_id, SUM(amount) as ad_spend
      FROM advertising
      WHERE date >= ? AND date <= ? AND nm_id > 0
      GROUP BY date, nm_id
    `).all(dateFrom, dateTo) as { date: string; nm_id: number; ad_spend: number }[];
    const adsMap = new Map<string, number>();
    for (const a of adsDaily) {
      adsMap.set(`${a.date}:${a.nm_id}`, a.ad_spend);
    }

    // ── 5. Хранение по артикулам (среднедневное из paid_storage) ──
    const storageRaw = d.prepare(`
      SELECT nm_id, SUM(warehouse_price) as total, COUNT(DISTINCT date) as days
      FROM paid_storage
      WHERE date >= ? AND date <= ?
      GROUP BY nm_id
    `).all(dateFrom, dateTo) as { nm_id: number; total: number; days: number }[];
    const storageDailyMap = new Map<number, number>();
    for (const r of storageRaw) {
      storageDailyMap.set(r.nm_id, r.days > 0 ? r.total / r.days : 0);
    }
    // Fallback: если paid_storage пуст, берём из realization (общее хранение / дни / кол-во артикулов)
    if (storageRaw.length === 0) {
      const storageFallback = d.prepare(`
        SELECT SUM(storage_fee) as total FROM realization WHERE rr_dt >= ? AND rr_dt <= ?
      `).get(econFrom, econTo) as Record<string, number>;
      const numArticles = unitEcon.size || 1;
      const fallbackDays = 14;
      const perArticleDaily = (storageFallback.total || 0) / fallbackDays / numArticles;
      for (const nm of unitEcon.keys()) {
        storageDailyMap.set(nm, perArticleDaily);
      }
    }

    // ── 6. Штрафы по артикулам (среднедневные из предыдущего периода) ──
    const penaltyRaw = d.prepare(`
      SELECT nm_id, SUM(penalty) as total
      FROM realization
      WHERE penalty != 0 AND rr_dt >= ? AND rr_dt <= ? AND nm_id > 0
      GROUP BY nm_id
    `).all(econFrom, econTo) as { nm_id: number; total: number }[];
    const econDays = Math.max(1, Math.round((new Date(econTo).getTime() - new Date(econFrom).getTime()) / 86400000) + 1);
    const penaltyDailyMap = new Map<number, number>();
    for (const r of penaltyRaw) {
      penaltyDailyMap.set(r.nm_id, r.total / econDays);
    }

    // ── 7. Общие расходы: приёмка + джем (из предыдущего периода, среднедневные) ──
    const acceptance = (d.prepare(`SELECT COALESCE(SUM(acceptance), 0) as v FROM realization WHERE rr_dt >= ? AND rr_dt <= ?`).get(econFrom, econTo) as Record<string, number>).v;
    const jam = (d.prepare(`SELECT COALESCE(SUM(deduction), 0) as v FROM realization WHERE bonus_type_name LIKE '%Джем%' AND rr_dt >= ? AND rr_dt <= ?`).get(econFrom, econTo) as Record<string, number>).v;
    const overheadDaily = (acceptance + jam) / econDays;

    // ── 8. Сборка: прогноз по дням ──
    interface DayForecast {
      date: string;
      orders: number;
      orders_rub: number;
      estimated_revenue: number;
      estimated_profit_before_ads: number;
      ad_spend: number;
      storage: number;
      penalties: number;
      overhead: number;
      estimated_profit: number;
      articles: ForecastArticle[];
    }
    interface ForecastArticle {
      nm_id: number; article: string; custom_name: string; orders: number; buyout: number;
      avg_price: number; cogs_unit: number; logistics_unit: number;
      commission_unit: number; tax_unit: number; profit_per_unit: number;
      ad_spend: number; storage: number; penalties: number;
      estimated_revenue: number; estimated_profit: number;
    }

    const dayMap = new Map<string, DayForecast>();

    for (const o of ordersDaily) {
      const econ = unitEcon.get(o.nm_id);
      if (!econ) continue;

      const buyout = buyoutMap.get(o.nm_id) || 0.80;
      const adSpend = adsMap.get(`${o.day}:${o.nm_id}`) || 0;
      const storageDaily = storageDailyMap.get(o.nm_id) || 0;
      const penaltyDaily = penaltyDailyMap.get(o.nm_id) || 0;
      const estSales = o.orders * buyout;
      const estRevenue = estSales * econ.avgPrice;
      const estProfitBeforeAds = estSales * econ.profitPerUnit - storageDaily - penaltyDaily;
      const estProfit = estProfitBeforeAds - adSpend;

      if (!dayMap.has(o.day)) {
        dayMap.set(o.day, {
          date: o.day, orders: 0, orders_rub: 0,
          estimated_revenue: 0, estimated_profit_before_ads: 0,
          ad_spend: 0, storage: 0, penalties: 0, overhead: Math.round(overheadDaily),
          estimated_profit: 0, articles: [],
        });
      }
      const day = dayMap.get(o.day)!;
      day.orders += o.orders;
      day.orders_rub += o.orders_rub;
      day.estimated_revenue += estRevenue;
      day.estimated_profit_before_ads += estProfitBeforeAds;
      day.ad_spend += adSpend;
      day.storage += storageDaily;
      day.penalties += penaltyDaily;
      day.estimated_profit += estProfit;
      day.articles.push({
        nm_id: o.nm_id, article: econ.article, custom_name: econ.customName,
        orders: o.orders, buyout: Math.round(buyout * 1000) / 10,
        avg_price: Math.round(econ.avgPrice),
        cogs_unit: Math.round(econ.cogsUnit),
        logistics_unit: Math.round(econ.logUnit),
        commission_unit: Math.round(econ.commissionUnit),
        tax_unit: Math.round(econ.taxUnit),
        profit_per_unit: Math.round(econ.profitPerUnit),
        ad_spend: Math.round(adSpend),
        storage: Math.round(storageDaily),
        penalties: Math.round(penaltyDaily),
        estimated_revenue: Math.round(estRevenue),
        estimated_profit: Math.round(estProfit),
      });
    }

    // Sort, subtract overhead, round
    const result = Array.from(dayMap.values())
      .sort((a, b) => a.date.localeCompare(b.date))
      .map(day => ({
        ...day,
        estimated_revenue: Math.round(day.estimated_revenue),
        estimated_profit_before_ads: Math.round(day.estimated_profit_before_ads),
        ad_spend: Math.round(day.ad_spend),
        storage: Math.round(day.storage),
        penalties: Math.round(day.penalties),
        estimated_profit: Math.round(day.estimated_profit - overheadDaily),
        articles: day.articles.sort((a, b) => b.estimated_profit - a.estimated_profit),
      }));

    // Running totals
    let runningProfit = 0;
    let runningRevenue = 0;
    const withRunning = result.map(day => {
      runningProfit += day.estimated_profit;
      runningRevenue += day.estimated_revenue;
      return { ...day, running_profit: runningProfit, running_revenue: runningRevenue };
    });

    // Meta: какой период использован для юнит-экономики
    const meta = { econFrom, econTo, econDays, articlesCount: unitEcon.size };

    return NextResponse.json({ days: withRunning, meta });
  } catch (error) {
    return apiError(error);
  }
}

